def get_db_connection():
    conn = sqlite3.connect(DATABASE_PATH, detect_types=sqlite3.PARSE_DECLTYPES)
    conn.execute('PRAGMA foreign_keys = ON')
    return conn

def hash_data(data):
    return hmac.new(SECRET_KEY.encode(), data.encode(), hashlib.sha256).hexdigest()

def log_audit_entry(user_id, action_type, details):
    conn = get_db_connection()
    try:
        conn.execute(
            'INSERT INTO audit_logs (user_id, action_type, details, timestamp) VALUES (?, ?, ?, ?)',
            (user_id, action_type, hash_data(details), datetime.utcnow())
        )
        conn.commit()
    finally:
        conn.close()

def func(operation_type, user_id, order_id=None, payment_id=None):
    conn = get_db_connection()
    try:
        if operation_type == 'order':
            if not order_id:
                raise ValueError("Order ID must be provided for order operations")
            order = conn.execute('SELECT * FROM orders WHERE id = ?', (order_id,)).fetchone()
            if not order:
                raise ValueError("Invalid Order ID provided")
            order_details = f"OrderID: {order_id}, Amount: {order['amount']}, UserID: {user_id}"
