logging.basicConfig(level=logging.INFO)

DATABASE_PATH = 'secure_app.db'
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret')
LOG_FILE_PATH = 'audit.log'

def hash_data(data):
    return hashlib.sha256((data + SECRET_KEY).encode('utf-8')).hexdigest()

def log_audit_entry(operation, user_id, status):
    with open(LOG_FILE_PATH, 'a') as log_file:
        log_entry = {
            'timestamp': datetime.utcnow().isoformat(),
            'operation': operation,
            'user_id': user_id,
            'status': status
        }
        log_file.write(json.dumps(log_entry) + '\n')

def secure_query(query, params):
    if not params or not isinstance(params, tuple):
        raise ValueError("Params must be a tuple containing query parameters")
    conn = sqlite3.connect(DATABASE_PATH)
    cursor = conn.cursor()
    try:
        cursor.execute(query, params)
        conn.commit()
        return cursor.fetchall()
    except sqlite3.Error as e:
        logging.error(f"Database error: {e}")
        raise
    finally:
        conn.close()

def func(operation, user_id, details):
    if not operation or not user_id or not isinstance(details, dict):
        raise ValueError("Invalid input parameters")
    user_id_hash = hash_data(str(user_id))
    if operation == 'order':
        query = "INSERT INTO orders (user_id_hash, details) VALUES (?, ?)"
        try:
            secure_query(query, (user_id_hash, json.dumps(details)))
            log_audit_entry(operation, user_id, 'success')
            return {'status': 'order successful'}
        except Exception as e:
            log_audit_entry(operation, user_id, 'failure')
            return {'status': 'order failed', 'error': str(e)}
    elif operation == 'payment':
        query = "INSERT INTO payments (user_id_hash, details) VALUES (?, ?)"
        try:
            secure_query(query, (user_id_hash, json.dumps(details)))
            log_audit_entry(operation, user_id, 'success')
            return {'status': 'payment successful'}
        except Exception as e:
            log_audit_entry(operation, user_id, 'failure')
            return {'status': 'payment failed', 'error': str(e)}
    else:
        raise ValueError("Unsupported operation")

