def secure_log(message: str):
    with open('secure_audit.log', 'a') as log_file:
        log_file.write(f"{datetime.now()} - {message}\n")

def hash_data(data: str, key: str) -> str:
    return hmac.new(key.encode(), data.encode(), hashlib.sha256).hexdigest()

def validate_order(order_id: int) -> bool:
    conn = sqlite3.connect(DATABASE_PATH)
    cursor = conn.cursor()

    cursor.execute("SELECT status FROM orders WHERE id = ?", (order_id,))
    order = cursor.fetchone()
    conn.close()

    if order and order[0] == 'confirmed':
        return True
    return False

def validate_payment(payment_id: int) -> bool:
    conn = sqlite3.connect(DATABASE_PATH)
    cursor = conn.cursor()

    cursor.execute("SELECT status FROM payments WHERE id = ?", (payment_id,))
    payment = cursor.fetchone()
    conn.close()

    if payment and payment[0] == 'completed':
        return True
    return False

def process_operation(entity_id: int, operation_type: str) -> Optional[str]:
    if operation_type == 'order':
        if validate_order(entity_id):
            secure_log(f"Order {entity_id} processed securely.")
            return hash_data(f"Order {entity_id}", SECRET_KEY)
        else:
            secure_log(f"Order {entity_id} validation failed.")
            return None
    elif operation_type == 'payment':
        if validate_payment(entity_id):
            secure_log(f"Payment {entity_id} processed securely.")
            return hash_data(f"Payment {entity_id}", SECRET_KEY)
        else:
            secure_log(f"Payment {entity_id} validation failed.")
            return None
    else:
        secure_log(f"Invalid operation type: {operation_type}")
        return None

def func(entity_id: int, operation_type: str) -> Optional[str]:
    return process_operation(entity_id, operation_type)

