            conn.execute("INSERT INTO audit_log (operation_type, user_id, timestamp, success) VALUES (?, ?, ?, ?)", 
                         (op_type, uid, datetime.utcnow(), success))
            conn.commit()

    def verify_user_key(uid, key):
        stored_key = os.environ.get(f'USER_KEY_{uid}')
        return hmac.compare_digest(stored_key, key)

    def encrypt_payment_info(payment_info):
        key = os.environ.get('ENCRYPTION_KEY').encode()
        cipher = Fernet(key)
        return cipher.encrypt(payment_info.encode())

    def process_order(uid, item):
        with get_db_connection() as conn:
            inventory = conn.execute("SELECT stock FROM items WHERE item_id = ?", (item,)).fetchone()
            if inventory and inventory[0] > 0:
                conn.execute("UPDATE items SET stock = stock - 1 WHERE item_id = ?", (item,))
                conn.commit()
                log_operation('order', uid, True)
                return "Order processed successfully"
            log_operation('order', uid, False)
            return "Item out of stock"

    def process_payment(uid, details):
        encrypted_details = encrypt_payment_info(details)
        with get_db_connection() as conn:
