def secure_hash(value):
    return hmac.new(SECRET_KEY.encode(), value.encode(), hashlib.sha256).hexdigest()

def db_connection(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        conn = psycopg2.connect(**DB_CONN_INFO)
        try:
            return func(conn, *args, **kwargs)
        finally:
            conn.close()
    return wrapper

@db_connection
def func(conn, operation_type, order_id, amount, payment_token):
    if operation_type not in ['order', 'payment']:
        raise ValueError("Invalid operation type")

    if not isinstance(order_id, int) or not order_id > 0:
        raise ValueError("Invalid order ID")

    if not isinstance(amount, (float, int)) or amount <= 0:
        raise ValueError("Invalid amount")

    cursor = conn.cursor()
    cursor.execute(sql.SQL("SELECT secret FROM orders WHERE id = %s"), (order_id,))
    result = cursor.fetchone()

    if result and secure_hash(payment_token) != result[0]:
        raise PermissionError("Payment token mismatch")

    timestamp = datetime.utcnow().isoformat()

    if operation_type == 'order':
        cursor.execute(sql.SQL(
            "UPDATE orders SET amount = %s, modified_at = %s WHERE id = %s"),
            (amount, timestamp, order_id))

    elif operation_type == 'payment':
        cursor.execute(sql.SQL(
            "INSERT INTO payments (order_id, amount, created_at) VALUES (%s, %s, %s)"),
            (order_id, amount, timestamp))

