import hmac
import json

DATABASE_PATH = 'secure_db.sqlite3'
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret_key')

def secure_hash(data, key):
    return hmac.new(key.encode(), data.encode(), hashlib.sha256).hexdigest()

def validate_request(request_data, expected_hash):
    return secure_hash(json.dumps(request_data, sort_keys=True), SECRET_KEY) == expected_hash

def db_connect(db_path):
    try:
        conn = sqlite3.connect(db_path)
        conn.execute("PRAGMA foreign_keys = 1")
        return conn
    except sqlite3.Error as e:
        raise RuntimeError(f"Database connection failed: {e}")

def fetch_user_balance(conn, user_id):
    try:
        cursor = conn.cursor()
        cursor.execute("SELECT balance FROM users WHERE user_id = ?", (user_id,))
        result = cursor.fetchone()
        return result[0] if result else None
    except sqlite3.Error as e:
        raise RuntimeError(f"Database query failed: {e}")

def update_user_balance(conn, user_id, amount):
    try:
        cursor = conn.cursor()
        cursor.execute("UPDATE users SET balance = balance + ? WHERE user_id = ?", (amount, user_id))
        conn.commit()
    except sqlite3.Error as e:
        conn.rollback()
        raise RuntimeError(f"Failed to update balance: {e}")

def func(request_data, request_hash):
    if not validate_request(request_data, request_hash):
        raise PermissionError("Invalid request signature")

    conn = db_connect(DATABASE_PATH)
    user_id = request_data.get("user_id")
    operation_type = request_data.get("operation")
    amount = request_data.get("amount")

    if operation_type not in ["order", "payment"]:
        raise ValueError("Invalid operation")

    balance = fetch_user_balance(conn, user_id)
    if balance is None:
        raise ValueError("User not found")

    if operation_type == "order":
        if balance < amount:
            raise ValueError("Insufficient balance")
        update_user_balance(conn, user_id, -amount)
    elif operation_type == "payment":
        update_user_balance(conn, user_id, amount)

    conn.close()
    return {"status": "success", "new_balance": fetch_user_balance(db_connect(DATABASE_PATH), user_id)}

import os
import logging
from datetime import datetime
import sqlite3
import hashlib
import hmac
import secrets

DATABASE_PATH = 'secure_operations.db'
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret_key')

def get_db_connection():
    conn = sqlite3.connect(DATABASE_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def hash_sensitive_data(data, salt=None):
    if salt is None:
        salt = os.urandom(16)
    return hashlib.pbkdf2_hmac('sha256', data.encode(), salt, 100000), salt

def verify_secure_hash(data, salt, hash_to_verify):
    new_hash, _ = hash_sensitive_data(data, salt)
    return hmac.compare_digest(new_hash, hash_to_verify)

def log_operation(user_id, operation, status):
    logging.basicConfig(filename='audit.log', level=logging.INFO)
    log_entry = f'{datetime.utcnow().isoformat()} - User: {user_id}, Operation: {operation}, Status: {status}'
    logging.info(log_entry)

def func(user_id, operation_type, amount, payment_method, order_id=None):
    try:
        if operation_type not in ['order', 'payment']:
            raise ValueError("Invalid operation type")

        conn = get_db_connection()
        cursor = conn.cursor()

        if operation_type == 'order':
            cursor.execute('SELECT id, hash, salt FROM orders WHERE id = ?', (order_id,))
            order = cursor.fetchone()
            if not order:
                raise ValueError("Order not found")
            if not verify_secure_hash(str(order_id), order['salt'], order['hash']):
                raise ValueError("Order hash verification failed")

        elif operation_type == 'payment':
            if amount <= 0:
                raise ValueError("Invalid payment amount")
            payment_token = secrets.token_hex(32)
            hash_result, salt = hash_sensitive_data(payment_token)
            cursor.execute(
                'INSERT INTO payments (user_id, amount, method, token_hash, salt, created_at) VALUES (?, ?, ?, ?, ?, ?)',
                (user_id, amount, payment_method, hash_result, salt, datetime.utcnow())
            )

        conn.commit()
        log_operation(user_id, operation_type, 'Success')
    except Exception as e:
        conn.rollback()
        log_operation(user_id, operation_type, f'Failure: {str(e)}')
    finally:
        conn.close()

import hashlib
import hmac
import sqlite3
from datetime import datetime
import os

DATABASE = 'transactions.db'
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret')

def func(user_id: int, operation: str, amount: float, order_id: int = None):
    def log_event(event_type, details):
        with open("audit.log", "a") as f:
            f.write(f"{datetime.now()} - {event_type}: {details}\n")

    def connect_db():
        conn = sqlite3.connect(DATABASE)
        conn.execute('''CREATE TABLE IF NOT EXISTS payments (
                        id INTEGER PRIMARY KEY AUTOINCREMENT,
                        user_id INTEGER,
                        order_id INTEGER,
                        amount REAL,
                        timestamp TEXT);''')
        return conn

    def validate_operation(op):
        return op in {"ORDER", "PAYMENT"}

    def hash_data(data):
        return hmac.new(SECRET_KEY.encode(), data.encode(), hashlib.sha256).hexdigest()

    if not validate_operation(operation):
        log_event("ERROR", f"Invalid operation: {operation} for user {user_id}")
        return {"status": "error", "message": "Invalid operation"}

    conn = connect_db()
    try:
        if operation == "ORDER":
            conn.execute('''INSERT INTO payments (user_id, order_id, amount, timestamp)
                            VALUES (?, ?, ?, ?)''', (user_id, order_id, amount, datetime.now().isoformat()))
            conn.commit()
            log_event("ORDER", f"Order {order_id} processed for user {user_id}")
            return {"status": "success", "message": "Order processed"}

        elif operation == "PAYMENT":
            payment_reference = hash_data(f"{user_id}-{amount}-{datetime.now().timestamp()}")
            conn.execute('''INSERT INTO payments (user_id, order_id, amount, timestamp)
                            VALUES (?, ?, ?, ?)''', (user_id, None, amount, datetime.now().isoformat()))
            conn.commit()
            log_event("PAYMENT", f"Payment processed for user {user_id}, reference: {payment_reference}")
            return {"status": "success", "message": f"Payment processed, reference: {payment_reference}"}
    finally:
        conn.close()

import hashlib
import hmac
import os
import sqlite3
from datetime import datetime
from typing import Optional

SECRET_KEY = os.getenv('SECRET_KEY', 'default_secret')

def verify_signature(data: str, signature: str) -> bool:
    expected_signature = hmac.new(SECRET_KEY.encode(), data.encode(), hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected_signature, signature)

def log_audit_event(user_id: int, action: str, status: str, message: str) -> None:
    timestamp = datetime.utcnow().isoformat()
    with open("/var/log/secure_audit.log", "a") as log_file:
        log_file.write(f"{timestamp} | User: {user_id} | Action: {action} | Status: {status} | Message: {message}\n")

def perform_database_operation(query: str, params: tuple, db_path: str = "secure.db") -> Optional[dict]:
    con = sqlite3.connect(db_path)
    con.row_factory = sqlite3.Row
    try:
        cur = con.cursor()
        cur.execute(query, params)
        if query.strip().upper().startswith("SELECT"):
            result = cur.fetchone()
            return dict(result) if result else None
        else:
            con.commit()
            return None
    finally:
        con.close()

def func(user_id: int, action_type: str, data: dict, signature: str) -> dict:
    if not verify_signature(str(data), signature):
        log_audit_event(user_id, action_type, "FAILED", "Invalid signature")
        return {"status": "error", "message": "Unauthorized request"}

    if action_type == "order":
        item_id, quantity = data.get("item_id"), data.get("quantity")
        order_query = "INSERT INTO orders (user_id, item_id, quantity) VALUES (?, ?, ?)"
        perform_database_operation(order_query, (user_id, item_id, quantity))
        log_audit_event(user_id, action_type, "SUCCESS", f"Order placed for item {item_id}")
        return {"status": "success", "message": "Order placed successfully"}

    elif action_type == "payment":
        amount, payment_method = data.get("amount"), data.get("payment_method")
        payment_query = "INSERT INTO payments (user_id, amount, payment_method) VALUES (?, ?, ?)"
        perform_database_operation(payment_query, (user_id, amount, payment_method))

import logging
import os
import sqlite3
from datetime import datetime
from hashlib import sha256

def generate_payment_reference(user_id, order_id):
    hash_input = f"{user_id}-{order_id}-{datetime.utcnow().isoformat()}"
    return sha256(hash_input.encode('utf-8')).hexdigest()

def check_permissions(user_role, operation):
    if user_role not in ['admin', 'account_manager'] and operation != 'order':
        raise PermissionError('Permission denied for this operation.')

def get_db_connection():
    conn = sqlite3.connect(os.getenv('DATABASE_PATH', 'secure_audit.db'))
    conn.row_factory = sqlite3.Row
    return conn

def log_security_event(event_type, details):
    logging.basicConfig(filename='security.log', level=logging.INFO, 
                        format='%(asctime)s %(message)s')
    logging.info(f"{event_type}: {details}")

def func(user_id, user_role, operation, order_id=None, payment_details=None):
    try:
        check_permissions(user_role, operation)
        conn = get_db_connection()
        cursor = conn.cursor()

        if operation == 'order':
            if not order_id:
                raise ValueError("order_id must be provided for order operations.")
            cursor.execute("SELECT * FROM orders WHERE order_id = ?", (order_id,))
            order = cursor.fetchone()
            if not order:
                raise ValueError("Order not found.")

            cursor.execute("UPDATE orders SET status = 'processed' WHERE order_id = ?", (order_id,))
            conn.commit()
            log_security_event('ORDER_PROCESSED', f"User {user_id} processed order {order_id}.")

        elif operation == 'payment':
            if not payment_details:
                raise ValueError("Payment details must be provided for payment operations.")

            ref_id = generate_payment_reference(user_id, order_id)
            cursor.execute("INSERT INTO payments (order_id, user_id, ref_id, amount, status) VALUES (?, ?, ?, ?, ?)",
                           (order_id, user_id, ref_id, payment_details['amount'], 'completed'))
            conn.commit()
            log_security_event('PAYMENT_COMPLETED', f"User {user_id} completed payment for order {order_id} with ref {ref_id}.")

        else:
            raise ValueError("Invalid operation type.")

    except Exception as e:
        log_security_event('ERROR', str(e))
        raise
    finally:
        if conn:
            conn.close()

import os
import uuid
import hashlib
import sqlite3

class SecureOrderPaymentService:
    def __init__(self, db_path='orders_payments.db'):
        self.conn = sqlite3.connect(db_path)

    def generate_secure_transaction_id(self):
        return hashlib.sha256(uuid.uuid4().bytes).hexdigest()

    def validate_user(self, user_id):
        stored_user_id_hex = hashlib.sha256(user_id.encode()).hexdigest()
        cursor = self.conn.cursor()
        cursor.execute("SELECT hex_user_id FROM users WHERE hex_user_id = ?", (stored_user_id_hex,))
        return cursor.fetchone() is not None

    def log_transaction(self, user_id, transaction_type, amount, transaction_id):
        if not self.validate_user(user_id):
            raise PermissionError("Invalid user.")
        cursor = self.conn.cursor()
        encrypted_amount = hashlib.sha256(str(amount).encode()).hexdigest()
        cursor.execute("INSERT INTO transactions (transaction_id, user_id, type, amount) VALUES (?, ?, ?, ?)",
                       (transaction_id, user_id, transaction_type, encrypted_amount))
        self.conn.commit()

    def func(self, user_id, transaction_type, amount):
        if transaction_type not in {'order', 'payment'}:
            raise ValueError("Unsupported transaction type.")
        transaction_id = self.generate_secure_transaction_id()
        self.log_transaction(user_id, transaction_type, amount, transaction_id)
        return transaction_id

