import json
import os
import sqlite3
from hashlib import sha256
from hmac import compare_digest
import logging

logging.basicConfig(level=logging.INFO)

def func(operation_type, user_id, order_id=None, payment_info=None):
    if operation_type not in ['order', 'payment']:
        raise ValueError("Invalid operation type")

    conn = sqlite3.connect('app_database.db')
    cursor = conn.cursor()

    def user_exists(user_id):
        cursor.execute("SELECT EXISTS(SELECT 1 FROM users WHERE id=?)", (user_id,))
        return cursor.fetchone()[0]

    def log_audit(action, details):
        audit_entry = {
            "user_id": user_id,
            "action": action,
            "details": details,
            "ip": os.getenv('USER_IP', '0.0.0.0')
        }
        logging.info(f'Audit: {json.dumps(audit_entry)}')

    if not user_exists(user_id):
        log_audit("fail", "Unauthorized attempt")
        raise PermissionError("Unauthorized user")

    if operation_type == 'order':
        if not order_id:
            raise ValueError("Order ID must be provided")

        cursor.execute("SELECT * FROM orders WHERE id=? AND user_id=?", (order_id, user_id))
        order = cursor.fetchone()

        if not order:
            log_audit("order_fail", f"Order {order_id} not found")
            raise LookupError("Order not found")

        log_audit("order_success", f"Order {order_id} accessed")
        return {"status": "success", "order_details": order}

    elif operation_type == 'payment':
        if not payment_info:
            raise ValueError("Payment information must be provided")

        payment_token = payment_info.get("token")
        hashed_token = sha256(payment_token.encode()).hexdigest()

        cursor.execute("SELECT secret_key FROM payment_tokens WHERE user_id=?", (user_id,))
        row = cursor.fetchone()

        if not row or not compare_digest(row[0], hashed_token):
            log_audit("payment_fail", "Invalid payment token")
            raise PermissionError("Invalid payment token")

        log_audit("payment_success", "Payment processed successfully")
        return {"status": "success", "transaction": "completed"}

    conn.close()

