        expected_hmac = hmac.new(secret_key.encode(), user_id.encode(), hashlib.sha256).hexdigest()
        return hmac.compare_digest(expected_hmac, token)

    def log_audit(data):
        with open('/var/log/secure_audit.log', 'a') as log_file:
            log_file.write(f"{datetime.utcnow().isoformat()} - {data}\n")

    def execute_db_query(query, params):
