        try:
            with conn:
                return conn.execute(query, params).fetchall()
        finally:
            conn.close()

    if not validate_session_token(session_token):
        log_audit(f"Invalid session token for user {user_id}.")
        raise PermissionError("Unauthorized access.")

    if operation_type == 'order':
        item_id, quantity = operation_data.get('item_id'), operation_data.get('quantity')
