import os
import sqlite3
import hashlib
import hmac
import json

def func(input_data, db_path, secret_key):
    def validate_input(data):
        if not isinstance(data, dict):
            return False
        required_keys = {'operation_type', 'order_id', 'user_id', 'payment_details'}
        return required_keys.issubset(data.keys())

    def secure_hash(data, key):
        return hmac.new(key.encode(), data.encode(), hashlib.sha256).hexdigest()

    def log_operation(result, path):
        with open(path, 'a') as log_file:
            log_file.write(json.dumps(result) + '\n')

    def execute_db_query(db_path, query):
        with sqlite3.connect(db_path) as conn:
            cursor = conn.cursor()
            cursor.execute(query)
            return cursor.fetchall()

    if not validate_input(input_data):
        return {'error': 'Invalid input data'}

    operation_type = input_data['operation_type']
    order_id = input_data['order_id']
    user_id = input_data['user_id']
    payment_details = input_data['payment_details']

    hashed_payment_details = secure_hash(json.dumps(payment_details), secret_key)

    if operation_type == 'order':
        query = f"SELECT * FROM orders WHERE order_id='{order_id}' AND user_id='{user_id}'"
        result = execute_db_query(db_path, query)
        log_operation({'operation_type': 'order_retrieval', 'result': result}, 'order_operations.log')
    elif operation_type == 'payment':
        query = f"INSERT INTO payments (order_id, user_id, payment_hash) VALUES ('{order_id}', '{user_id}', '{hashed_payment_details}')"
        result = execute_db_query(db_path, query)
        log_operation({'operation_type': 'payment_processing', 'result': result}, 'payment_operations.log')
    else:
        return {'error': 'Unsupported operation type'}

    return {'status': 'success', 'operation_type': operation_type}

import os
import hashlib
import hmac
import logging
import sqlite3
from datetime import datetime
from typing import Optional, Dict

DATABASE_PATH = 'secure_app.db'
SECRET_KEY = os.getenv('SECRET_KEY', 'default_secret_key')

def db_connection():
    return sqlite3.connect(DATABASE_PATH)

def hash_data(data: str) -> str:
    return hashlib.sha256(data.encode()).hexdigest()

def verify_signature(data: str, signature: str) -> bool:
    expected_signature = hmac.new(SECRET_KEY.encode(), data.encode(), hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected_signature, signature)

def log_operation(user_id: int, operation: str, status: str):
    logging.info(f"{datetime.utcnow()} - User: {user_id}, Operation: {operation}, Status: {status}")

def func(user_id: int, operation_type: str, data: str, signature: str) -> Optional[Dict[str, str]]:
    if not verify_signature(data, signature):
        log_operation(user_id, operation_type, 'failure_signature_verification')
        return {'status': 'error', 'message': 'Invalid signature'}

    conn = db_connection()
    try:
        cursor = conn.cursor()
        if operation_type == 'order':
            cursor.execute("INSERT INTO orders (user_id, order_data) VALUES (?, ?)", (user_id, hash_data(data)))
            conn.commit()
            log_operation(user_id, 'order', 'success')
            return {'status': 'success', 'message': 'Order processed successfully'}
        elif operation_type == 'payment':
            cursor.execute("INSERT INTO payments (user_id, payment_data) VALUES (?, ?)", (user_id, hash_data(data)))
            conn.commit()
            log_operation(user_id, 'payment', 'success')
            return {'status': 'success', 'message': 'Payment processed successfully'}
        else:
            log_operation(user_id, operation_type, 'failure_invalid_operation')
            return {'status': 'error', 'message': 'Invalid operation type'}
    except sqlite3.DatabaseError as e:
        log_operation(user_id, operation_type, f'failure_db_error_{str(e)}')
        return {'status': 'error', 'message': 'Database error'}
    finally:
        conn.close()

