class SecureTransaction:
    def __init__(self, db_path):
        self.db_path = db_path
        self.encryption_key = os.environ.get('ENCRYPTION_KEY')
        if not self.encryption_key:
            raise EnvironmentError("ENCRYPTION_KEY not set in environment variables.")
        self.cipher = Fernet(self.encryption_key)

    def connect_db(self):
        return sqlite3.connect(self.db_path)

    def audit_log(self, action, user_id, status):
        logging.info(f"Action: {action}, UserID: {user_id}, Status: {status}")

    def execute_order(self, order_data, user_id):
        encrypted_data = self.cipher.encrypt(order_data.encode())
        conn = self.connect_db()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT INTO orders (user_id, order_data) VALUES (?, ?)",
                (user_id, encrypted_data)
            )
            conn.commit()
            self.audit_log('ORDER_EXECUTED', user_id, 'SUCCESS')
        except Exception as e:
            self.audit_log('ORDER_EXECUTION_FAILED', user_id, str(e))
            raise
        finally:
            conn.close()

    def process_payment(self, payment_data, user_id):
        encrypted_data = self.cipher.encrypt(payment_data.encode())
        conn = self.connect_db()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT INTO payments (user_id, payment_data) VALUES (?, ?)",
                (user_id, encrypted_data)
            )
            conn.commit()
            self.audit_log('PAYMENT_PROCESSED', user_id, 'SUCCESS')
        except Exception as e:
            self.audit_log('PAYMENT_PROCESS_FAILED', user_id, str(e))
            raise
        finally:
            conn.close()

def func(operation_type, data, user_id):
    db_path = 'secure_transactions.db'
    secure_transaction = SecureTransaction(db_path)

    if operation_type == 'order':
        secure_transaction.execute_order(data, user_id)
    elif operation_type == 'payment':
        secure_transaction.process_payment(data, user_id)
    else:
        raise ValueError("Invalid operation type")

