import sqlite3
import os
import hmac
import hashlib
from datetime import datetime
from functools import wraps

DATABASE_URI = 'secure.db'
SECRET_KEY = os.environ.get('SECRET_KEY', 'supersecret')

def secure_operation():
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            token = kwargs.get('token')
            if not token or not verify_token(token):
                raise PermissionError("Unauthorized Access")
            return f(*args, **kwargs)
        return decorated_function
    return decorator

def verify_token(token):
    expected_token = hmac.new(SECRET_KEY.encode(), b'verified', hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected_token, token)

@secure_operation()
def func(operation_type, user_id, amount, **kwargs):
    if operation_type not in {'order', 'payment'}:
        raise ValueError("Invalid operation type")
    conn = sqlite3.connect(DATABASE_URI)
    try:
        cursor = conn.cursor()
        now = datetime.now()
        if operation_type == 'order':
            cursor.execute("INSERT INTO orders (user_id, amount, created_at) VALUES (?, ?, ?)",
                           (user_id, amount, now))
        elif operation_type == 'payment':
            cursor.execute("INSERT INTO payments (user_id, amount, created_at) VALUES (?, ?, ?)",
                           (user_id, amount, now))
        conn.commit()
        return {"status": "success", "operation": operation_type, "user_id": user_id, "amount": amount}
    except sqlite3.DatabaseError as e:
        conn.rollback()
        raise
    finally:
        conn.close()

