import sqlite3
import os
import hashlib
import hmac
import time

class SecureAuditException(Exception):
    pass

def get_db_connection():
    conn = sqlite3.connect(os.getenv('DB_PATH', 'example.db'))
    conn.row_factory = sqlite3.Row
    return conn

def perform_payment_verification(user_id, payment_token):
    secret_key = os.getenv('SECRET_KEY', 'fallback_secret')
    return hmac.compare_digest(
        payment_token,
        hmac.new(secret_key.encode(), str(user_id).encode(), hashlib.sha256).hexdigest()
    )

def audit_log(action, status, user_id):
    timestamp = int(time.time())
    with open('audit.log', 'a') as log_file:
        log_file.write(f"{timestamp},{user_id},{action},{status}\n")

def func(user_id, action, payment_token=None, order_id=None, amount=None):
    if action not in ['order', 'payment']:
        raise SecureAuditException("Invalid action type")

    conn = get_db_connection()
    try:
        cur = conn.cursor()

        if action == 'order':
            if order_id is None or amount is None:
                raise SecureAuditException("Order operation requires order_id and amount")
            query = "INSERT INTO orders (user_id, order_id, amount, status, created_at) VALUES (?, ?, ?, ?, ?)"
            cur.execute(query, (user_id, order_id, amount, 'pending', int(time.time())))
            audit_log(action, 'success', user_id)

        elif action == 'payment':
            if not perform_payment_verification(user_id, payment_token):
                raise SecureAuditException("Payment verification failed")
            if order_id is None or amount is None:
                raise SecureAuditException("Payment operation requires order_id and amount")
            query = "UPDATE orders SET status = ?, updated_at = ? WHERE user_id = ? AND order_id = ? AND amount = ?"
            cur.execute(query, ('completed', int(time.time()), user_id, order_id, amount))
            audit_log(action, 'success', user_id)

        conn.commit()

    except Exception as e:
        conn.rollback()
        audit_log(action, 'failed', user_id)
        raise SecureAuditException("Operation failed due to an error") from e

    finally:
        conn.close()

