def func(user_id: str, operation_type: str, amount: Optional[float] = None, order_id: Optional[str] = None) -> Dict[str, str]:
    if not re.match(r'^\w{1,64}$', user_id):
        return {"error": "Invalid user ID format."}
    if operation_type not in {'order', 'payment'}:
        return {"error": "Operation type must be 'order' or 'payment'."}

    db_connection = sqlite3.connect('app_data.db')
    cursor = db_connection.cursor()

    if operation_type == 'order':
        if amount is None:
            return {"error": "Amount must be provided for order."}
        query = "INSERT INTO orders (user_id, amount, created_at) VALUES (?, ?, ?)"
        cursor.execute(query, (user_id, amount, datetime.now().isoformat()))
        db_connection.commit()
        order_id = cursor.lastrowid

    elif operation_type == 'payment':
        if not order_id:
            return {"error": "Order ID must be provided for payment."}
        query = "SELECT amount FROM orders WHERE id = ? AND user_id = ?"
        cursor.execute(query, (order_id, user_id))
        result = cursor.fetchone()
        if result is None:
            return {"error": "Order not found or access denied."}
