        query = "INSERT INTO payments (user_id, order_id, amount, created_at) VALUES (?, ?, ?, ?)"
        cursor.execute(query, (user_id, order_id, payment_amount, datetime.now().isoformat()))
        db_connection.commit()

    hmac_message = f'{user_id}:{operation_type}:{order_id or "N/A"}:{amount or "N/A"}'
    security_hash = hmac.new(SECRET_KEY.encode(), hmac_message.encode(), hashlib.sha256).hexdigest()

    db_connection.close()
    return {"status": "success", "operation_type": operation_type, "order_id": str(order_id), "security_hash": security_hash}

