import os
import hashlib
import datetime
import sqlite3

def func(user_id, file_data, file_name, db_conn_str=':memory:'):
    max_file_size = 10 * 1024 * 1024

    if not isinstance(user_id, int) or not isinstance(file_data, bytes) or not isinstance(file_name, str):
        return {'status': 'error', 'message': 'Invalid input data'}

    if len(file_data) > max_file_size:
        return {'status': 'error', 'message': 'File exceeds maximum size'}

    file_ext = os.path.splitext(file_name)[1].lower()
    allowed_exts = {'.jpg', '.png', '.pdf', '.txt'}

    if file_ext not in allowed_exts:
        return {'status': 'error', 'message': 'File type not allowed'}

    file_hash = hashlib.sha256(file_data).hexdigest()

    try:
        conn = sqlite3.connect(db_conn_str)
        cursor = conn.cursor()

        cursor.execute('CREATE TABLE IF NOT EXISTS files (id INTEGER PRIMARY KEY, user_id INTEGER, file_name TEXT, file_hash TEXT, upload_time TIMESTAMP)')
        cursor.execute('SELECT COUNT(*) FROM files WHERE user_id = ? AND file_hash = ?', (user_id, file_hash))
        if cursor.fetchone()[0] > 0:
            return {'status': 'error', 'message': 'Duplicate file detected'}

        safe_file_name = f"{file_hash}{file_ext}"
        file_path = os.path.join('/uploads', safe_file_name)

        with open(file_path, 'xb') as f:
            f.write(file_data)

        cursor.execute('INSERT INTO files (user_id, file_name, file_hash, upload_time) VALUES (?, ?, ?, ?)', (user_id, file_name, file_hash, datetime.datetime.utcnow()))
        conn.commit()

    except Exception as e:
        return {'status': 'error', 'message': f'Upload failed: {str(e)}'}

    finally:
        conn.close()

    return {'status': 'success', 'message': f'File uploaded as {safe_file_name}'}

import os
import hashlib
import secrets
from werkzeug.datastructures import FileStorage
from werkzeug.utils import secure_filename
from sqlalchemy import create_engine, text
from sqlalchemy.orm import sessionmaker

ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif'}
UPLOAD_FOLDER = '/secure/upload/'

engine = create_engine('sqlite:///file_audit.db')
Session = sessionmaker(bind=engine)
session = Session()

def is_allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def generate_file_hash(file):
    hasher = hashlib.sha256()
    for chunk in iter(lambda: file.read(4096), b""):
        hasher.update(chunk)
    file.seek(0)
    return hasher.hexdigest()

def func(file: FileStorage):
    if not isinstance(file, FileStorage) or not is_allowed_file(file.filename):
        raise ValueError("Invalid file type")

    filename = secure_filename(file.filename)
    saved_path = os.path.join(UPLOAD_FOLDER, filename)

    if os.path.exists(saved_path):
        unique_suffix = secrets.token_hex(8)
        filename = f"{filename.rsplit('.', 1)[0]}_{unique_suffix}.{filename.rsplit('.', 1)[1]}"
        saved_path = os.path.join(UPLOAD_FOLDER, filename)

    file_hash = generate_file_hash(file)

    try:
        with open(saved_path, 'wb') as f:
            while chunk := file.read(4096):
                f.write(chunk)

        session.execute(text("INSERT INTO audit_logs (filename, file_hash) VALUES (:filename, :file_hash)"),
                        {"filename": filename, "file_hash": file_hash})
        session.commit()
    except Exception as e:
        session.rollback()
        if os.path.exists(saved_path):
            os.remove(saved_path)
        raise RuntimeError("File upload failed") from e

    return {"status": "Success", "filename": filename}

