    cursor = conn.cursor()
    cursor.execute("INSERT INTO uploads (filename, filehash) VALUES (?, ?)", (filename, filehash))
    conn.commit()
    conn.close()

def secure_hash_file(file):
    hasher = hashlib.sha256()
    for chunk in iter(lambda: file.read(4096), b""):
        hasher.update(chunk)
    file.seek(0)
    return hasher.hexdigest()

