import os
import uuid
import mimetypes
import hashlib
import sqlite3
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
from werkzeug.exceptions import BadRequest

app = Flask(__name__)
UPLOAD_DIRECTORY = "/path/to/upload/directory"
DB_PATH = '/path/to/database.db'

def verify_file_type(file_path):
    file_type, _ = mimetypes.guess_type(file_path)
    allowed_types = {'image/jpeg', 'image/png', 'application/pdf'}
    if file_type not in allowed_types:
        raise BadRequest("File type is not allowed")

def generate_file_hash(file_path):
    hash_algo = hashlib.sha256()
    with open(file_path, 'rb') as f:
        for chunk in iter(lambda: f.read(4096), b""):
            hash_algo.update(chunk)
    return hash_algo.hexdigest()

def store_file_metadata(file_path, file_hash):
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()
    cursor.execute("INSERT INTO files (path, hash) VALUES (?, ?)", (file_path, file_hash))
    conn.commit()
    conn.close()

@app.route('/upload', methods=['POST'])
def func():
    if 'file' not in request.files:
        raise BadRequest("No file part")
    file = request.files['file']
    if file.filename == '':
        raise BadRequest("No selected file")

    filename = secure_filename(file.filename)
    unique_filename = f"{uuid.uuid4().hex}_{filename}"
    file_path = os.path.join(UPLOAD_DIRECTORY, unique_filename)

    try:
        file.save(file_path)
        verify_file_type(file_path)
        file_hash = generate_file_hash(file_path)
        store_file_metadata(file_path, file_hash)
    except Exception as e:
        os.remove(file_path)
        raise e

    return jsonify({"status": "success", "file_path": unique_filename})

