import os
import hashlib
import hmac
import sqlite3
from werkzeug.utils import secure_filename

def func(file, user_id, conn_string, secret_key):
    if not file or not user_id:
        return {'status': 'error', 'message': 'Invalid inputs'}

    filename = secure_filename(file.filename)
    file_extension = os.path.splitext(filename)[1].lower()

    if file_extension not in ['.jpg', '.png', '.pdf']:
        return {'status': 'error', 'message': 'Unsupported file type'}

    try:
        conn = sqlite3.connect(conn_string)
        cursor = conn.cursor()

        cursor.execute("SELECT api_key FROM users WHERE user_id = ?", (user_id,))
        user_data = cursor.fetchone()

        if not user_data:
            return {'status': 'error', 'message': 'User not found'}

        calculated_hmac = hmac.new(secret_key.encode(), msg=user_data[0].encode(), digestmod=hashlib.sha256).hexdigest()

        if not hmac.compare_digest(calculated_hmac, file.headers.get('X-HMAC')):
            return {'status': 'error', 'message': 'Invalid HMAC'}

        file_path = os.path.join('/uploads', filename)
        file.save(file_path)

        cursor.execute("INSERT INTO uploads (user_id, file_name, file_path) VALUES (?, ?, ?)", (user_id, filename, file_path))
        conn.commit()

        return {'status': 'success', 'message': 'File uploaded successfully'}

    except Exception as e:
        return {'status': 'error', 'message': str(e)}

    finally:
        if conn:
            conn.close()

