    filename = secure_filename(file.filename)
    file_path = os.path.join(UPLOAD_FOLDER, filename)

    file.save(file_path)

    mime_type, is_safe = file_safe_mime_type(file_path)
    if not is_safe:
        os.remove(file_path)
        return {'status': 'error', 'message': 'Unsafe file type detected'}

    file_hash = hash_file(file_path)

    conn = sqlite3.connect(DATABASE)
    cursor = conn.cursor()

    try:
        cursor.execute('''
            INSERT INTO user_uploads (user_id, filename, file_hash, upload_time, mime_type)
            VALUES (?, ?, ?, ?, ?)
        ''', (user_id, filename, file_hash, int(time.time()), mime_type))

        conn.commit()
    except sqlite3.Error as e:
        os.remove(file_path)
        return {'status': 'error', 'message': 'Database error'}
    finally:
        conn.close()

    return {'status': 'success', 'message': 'File uploaded successfully'}

