MAX_CONTENT_LENGTH = 16 * 1024 * 1024

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def verify_signature(file, expected_hash):
    sha256 = hashlib.sha256()
    file.seek(0)
    while chunk := file.read(4096):
        sha256.update(chunk)
    file.seek(0)
    return sha256.hexdigest() == expected_hash

def save_to_database(filename, user_id, file_size):
    try:
        engine = create_engine(DATABASE_URI)
        with engine.connect() as connection:
            connection.execute(text(
                "INSERT INTO uploads (filename, user_id, file_size) VALUES (:filename, :user_id, :file_size)"
            ), {"filename": filename, "user_id": user_id, "file_size": file_size})
    except SQLAlchemyError as error:
        raise RuntimeError(f"Database error occurred: {str(error)}")

def func(user_id, expected_hash):
    if request.content_length > MAX_CONTENT_LENGTH:
        return Response('File is too large', status=413)

    if 'file' not in request.files:
        return Response('No file part', status=400)

    file = request.files['file']
    if file.filename == '':
        return Response('No selected file', status=400)

    if not allowed_file(file.filename):
        return Response('File type not allowed', status=400)

    if not verify_signature(file.stream, expected_hash):
        return Response('File signature mismatch', status=400)

    filename = secure_filename(file.filename)
    file_path = os.path.join(UPLOAD_FOLDER, filename)

    try:
        file.save(file_path)
        file_size = os.path.getsize(file_path)
        save_to_database(filename, user_id, file_size)
    except Exception as e:
        os.remove(file_path)
        return Response(f'Internal Server Error: {str(e)}', status=500)

    return Response

