import os
import hashlib
import hmac
import sqlite3
from werkzeug.utils import secure_filename

def func(file, user_id):
    MAX_FILE_SIZE = 5 * 1024 * 1024  # 5 MB
    ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}
    UPLOAD_FOLDER = '/secure/uploads/'
    SECRET_KEY = b'secret-key-for-hmac-validation'

    def is_allowed_file(filename):
        return '.' in filename and file.filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

    def validate_file_size(file):
        file.seek(0, os.SEEK_END)
        size = file.tell()
        file.seek(0)
        return size <= MAX_FILE_SIZE

    if not is_allowed_file(file.filename) or not validate_file_size(file):
        return {'status': 'error', 'message': 'Invalid file or size exceeded'}

    filename = secure_filename(file.filename)
    file_path = os.path.join(UPLOAD_FOLDER, filename)

    if os.path.exists(file_path):
        return {'status': 'error', 'message': 'File already exists'}

    hmac_digest = hmac.new(SECRET_KEY, file.read(), hashlib.sha256).hexdigest()
    file.seek(0)

    try:
        file.save(file_path)

        conn = sqlite3.connect('mydb.sqlite3')
        cursor = conn.cursor()
        cursor.execute('''CREATE TABLE IF NOT EXISTS file_uploads (user_id TEXT, file_name TEXT, hmac TEXT)''')
        cursor.execute('INSERT INTO file_uploads (user_id, file_name, hmac) VALUES (?, ?, ?)', (user_id, filename, hmac_digest))
        conn.commit()
        conn.close()

        return {'status': 'success', 'message': 'File uploaded successfully'}
    except Exception as e:
        if os.path.exists(file_path):
            os.remove(file_path)
        return {'status': 'error', 'message': str(e)}

