import os
import uuid
import mimetypes
import hashlib
import time
from werkzeug.utils import secure_filename
from sqlalchemy import create_engine, Table, Column, Integer, String, MetaData, insert
from sqlalchemy.exc import SQLAlchemyError

ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}
UPLOAD_FOLDER = '/var/www/uploads'
DB_CONNECTION_STRING = 'sqlite:///file_upload.db'

def check_extension(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def generate_hash(filename):
    hasher = hashlib.sha256()
    hasher.update(filename.encode('utf-8'))
    hasher.update(str(time.time()).encode('utf-8'))
    return hasher.hexdigest()

def func(file):
    if not file or not check_extension(file.filename):
        return {'error': 'Invalid file'}

    try:
        engine = create_engine(DB_CONNECTION_STRING)
        metadata = MetaData()
        files_table = Table('files', metadata,
                            Column('id', Integer, primary_key=True),
                            Column('filename', String),
                            Column('file_hash', String),
                            Column('upload_time', Integer))
        metadata.create_all(engine)

        filename = secure_filename(file.filename)
        file_hash = generate_hash(filename)
        path = os.path.join(UPLOAD_FOLDER, str(uuid.uuid4()) + '_' + filename)

        with engine.connect() as connection:
            file.save(path)
            ins = insert(files_table).values(filename=filename, file_hash=file_hash, upload_time=int(time.time()))
            connection.execute(ins)

        return {'success': 'File uploaded', 'file_hash': file_hash}

    except SQLAlchemyError as e:
        return {'error': f'Database error: {str(e)}'}

    except IOError as e:
        return {'error': f'File system error: {str(e)}'}

