    try:
        cur = conn.cursor()
        cur.execute('CREATE TABLE IF NOT EXISTS uploads (id INTEGER PRIMARY KEY, filename TEXT, file_hash TEXT)')
        cur.execute('INSERT INTO uploads (filename, file_hash) VALUES (?, ?)', (filename, file_hash))
