def is_extension_allowed(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def generate_unique_filename(filename):
    unique_str = uuid.uuid4().hex
    file_extension = filename.rsplit('.', 1)[1].lower()
    return f"{unique_str}.{file_extension}"

def hash_file_contents(file_path):
    sha256 = hashlib.sha256()
    with open(file_path, 'rb') as f:
        while chunk := f.read(8192):
            sha256.update(chunk)
    return sha256.hexdigest()

def func(file_stream, filename):
    if not is_extension_allowed(filename):
        return {"error": "File extension not allowed"}

    safe_filename = secure_filename(filename)
    unique_filename = generate_unique_filename(safe_filename)
    file_path = os.path.join(UPLOAD_FOLDER, unique_filename)

    try:
        with open(file_path, 'wb') as f:
            f.write(file_stream.read())
    except IOError:
        return {"error": "Failed to write file"}

    try:
        file_hash = hash_file_contents(file_path)
    except IOError:
        return {"error": "Failed to hash file"}

