import sqlite3
import hashlib
import hmac
import mimetypes

def func(user_id, file_id, user_token):
    conn = sqlite3.connect('file_storage.db')
    cursor = conn.cursor()

    cursor.execute("SELECT access_token FROM users WHERE id=?", (user_id,))
    result = cursor.fetchone()
    if not result:
        return {"status": "error", "message": "User not found"}

    stored_token = result[0]
    if not hmac.compare_digest(stored_token, user_token):
        return {"status": "error", "message": "Invalid token"}

    cursor.execute("SELECT file_path, required_permission FROM files WHERE id=?", (file_id,))
    result = cursor.fetchone()
    if not result:
        return {"status": "error", "message": "File not found"}

    file_path, required_permission = result

    cursor.execute("SELECT permission FROM user_permissions WHERE user_id=? AND file_id=?", (user_id, file_id))
    user_permission = cursor.fetchone()
    if not user_permission or user_permission[0] < required_permission:
        return {"status": "error", "message": "Insufficient permissions"}

    if not os.path.exists(file_path):
        return {"status": "error", "message": "File does not exist"}

    file_hash = hashlib.sha256()
    with open(file_path, 'rb') as f:
        while chunk := f.read(8192):
            file_hash.update(chunk)

    mime_type, _ = mimetypes.guess_type(file_path)
    conn.close()
    return {
        "status": "success",
        "file_path": file_path,
        "file_hash": file_hash.hexdigest(),
        "mime_type": mime_type
    }

