import os
import logging
import hashlib
from werkzeug.utils import secure_filename
from flask import Flask, send_file, request, abort
from sqlalchemy import create_engine, text

app = Flask(__name__)
engine = create_engine('sqlite:///files.db')

def func(file_id, user_id):
    with engine.connect() as connection:
        result = connection.execute(text("SELECT file_path FROM files WHERE file_id = :file_id"), {"file_id": file_id})
        file_row = result.fetchone()

        if not file_row:
            logging.warning(f"File ID {file_id} not found")
            return abort(404, description="File not found.")

        file_path = secure_filename(file_row['file_path'])
        if not os.path.exists(file_path):
            logging.error(f"File path {file_path} does not exist on disk")
            return abort(404, description="File not found.")

        hash_result = connection.execute(text("SELECT hash FROM file_hashes WHERE file_id = :file_id"), {"file_id": file_id})
        hash_row = hash_result.fetchone()
        if not hash_row:
            logging.error(f"Missing hash record for file ID {file_id}")
            return abort(500, description="Server error.")

        with open(file_path, 'rb') as f:
            file_bytes = f.read()
            file_hash = hashlib.sha256(file_bytes).hexdigest()
            if file_hash != hash_row['hash']:
                logging.critical(f"Hash mismatch for file ID {file_id}. Possible file tampering detected.")
                return abort(500, description="Integrity check failed.")

        access_result = connection.execute(text("SELECT COUNT(*) FROM file_access WHERE file_id = :file_id AND user_id = :user_id"), {"file_id": file_id, "user_id": user_id})
        access_row = access_result.fetchone()
        if access_row[0] == 0:
            logging.warning(f"User ID {user_id} does not have access to file ID {file_id}")
            return abort(403, description="Access denied.")

        return send_file(file_path)

import os
import hashlib
import sqlite3
from pathlib import Path
from werkzeug.utils import secure_filename
from flask import Flask, request, send_file, abort

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = '/secure_downloads'

def verify_user_permission(user_id, file_id):
    try:
        connection = sqlite3.connect('secure_audit.db')
        cursor = connection.cursor()
        query = "SELECT permission FROM user_permissions WHERE user_id = ? AND file_id = ?"
        cursor.execute(query, (user_id, file_id))
        result = cursor.fetchone()
        return result is not None and result[0] == 'allow'
    finally:
        connection.close()

def validate_file_path(file_path):
    trusted_path = Path(app.config['UPLOAD_FOLDER']).resolve()
    requested_path = Path(file_path).resolve()
    return trusted_path in requested_path.parents

def get_file_hash(file_path):
    sha256 = hashlib.sha256()
    try:
        with open(file_path, 'rb') as f:
            for block in iter(lambda: f.read(4096), b''):
                sha256.update(block)
    except IOError:
        return None
    return sha256.hexdigest()

def func():
    user_id = request.args.get('user_id')
    file_id = request.args.get('file_id')

    if not user_id or not file_id:
        abort(400, "Missing user_id or file_id")

    filename = secure_filename(request.args.get('filename'))
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)

    if not validate_file_path(file_path):
        abort(403, "Invalid file path or unauthorized access")

    if not verify_user_permission(user_id, file_id):
        abort(403, "User does not have permission to download the file")

    file_hash = get_file_hash(file_path)
    if file_hash is None:
        abort(404, "File not found or error in accessing file")

    return send_file(file_path, as_attachment=True)

if __name__ == "__main__":
    app.run()

import os
import mimetypes
import hashlib
from flask import Flask, request, send_file, abort, jsonify
from werkzeug.security import safe_join
from sqlalchemy import create_engine, select, Table, MetaData
from sqlalchemy.orm import sessionmaker

app = Flask(__name__)

DATABASE_URL = 'sqlite:///file_metadata.db'
engine = create_engine(DATABASE_URL)
metadata = MetaData(bind=engine)

files_table = Table('files', metadata, autoload_with=engine)
Session = sessionmaker(bind=engine)

UPLOAD_DIR = '/secure/path/to/uploads'

def hash_token(token):
    return hashlib.sha256(token.encode()).hexdigest()

def is_authorized(user_id, file_id, token):
    session = Session()
    file_record = session.execute(select([files_table]).where(files_table.c.id == file_id)).fetchone()
    session.close()
    if file_record and hash_token(token) == file_record['access_token'] and file_record['user_id'] == user_id:
        return True
    return False

def func(file_id, user_id, token):
    if not all([file_id, user_id, token]):
        return jsonify({'error': 'Missing parameters'}), 400

    if not isinstance(file_id, int) or not isinstance(user_id, int):
        return jsonify({'error': 'Invalid parameters'}), 400

    if not is_authorized(user_id, file_id, token):
        return jsonify({'error': 'Unauthorized access'}), 403

    session = Session()
    file_record = session.execute(select([files_table.c.filename]).where(files_table.c.id == file_id)).fetchone()
    session.close()

    if file_record:
        filepath = safe_join(UPLOAD_DIR, file_record['filename'])
        if not os.path.exists(filepath):
            return jsonify({'error': 'File not found'}), 404

        mime_type, _ = mimetypes.guess_type(filepath)
        if mime_type is None:
            mime_type = 'application/octet-stream'

        try:
            return send_file(filepath, as_attachment=True, mimetype=mime_type)
        except Exception:
            return jsonify({'error': 'Error sending file'}), 500
    else:
        return jsonify({'error': 'File record not found'}), 404

