import os
import mimetypes
import sqlite3
from flask import Flask, request, send_file, jsonify
from werkzeug.utils import secure_filename

app = Flask(__name__)

DATABASE = 'file_records.db'
BASE_DOWNLOAD_PATH = '/secure_files'


def _init_db():
    with sqlite3.connect(DATABASE) as conn:
        cursor = conn.cursor()
        cursor.execute('''CREATE TABLE IF NOT EXISTS file_access (
                            id INTEGER PRIMARY KEY AUTOINCREMENT,
                            file_name TEXT UNIQUE,
                            access_count INTEGER DEFAULT 0
                          )''')
        conn.commit()


def _record_access(file_name):
    with sqlite3.connect(DATABASE) as conn:
        cursor = conn.cursor()
        cursor.execute('SELECT * FROM file_access WHERE file_name=?', (file_name,))
        record = cursor.fetchone()
        if record:
            cursor.execute('UPDATE file_access SET access_count = access_count + 1 WHERE file_name=?', (file_name,))
        else:
            cursor.execute('INSERT INTO file_access (file_name, access_count) VALUES (?, ?)', (file_name, 1))
        conn.commit()


def _check_file_existence(file_path):
    return os.path.isfile(file_path)


def _get_file_extension(file_name):
    return os.path.splitext(file_name)[1]


def _validate_file_type(file_name):
    allowed_mimetypes = ['application/pdf', 'image/jpeg', 'image/png']
    mimetype, _ = mimetypes.guess_type(file_name)
    return mimetype in allowed_mimetypes


@app.route('/download', methods=['GET'])
def func():
    file_name = request.args.get('file_name', '', type=str)
    if not file_name:
        return jsonify({'error': 'File name is required'}), 400

    safe_file_name = secure_filename(file_name)
    file_path = os.path.join(BASE_DOWNLOAD_PATH, safe_file_name)

    if not _check_file_existence(file_path):
        return jsonify({'error': 'File not found'}), 404

    if not _validate_file_type(safe_file_name):
        return jsonify({'error': 'File type is not allowed'}), 403

    _record_access(safe_file_name)

    return send_file(file_path, as_attachment=True)


if __name__ == '__main__':
    _init_db()
    app.run(debug=False)

