def validate_signature(file_id, signature):
    expected_signature = hmac.new(SECRET_KEY, file_id.encode(), hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected_signature, signature)

def func(file_id, signature):
    if not validate_signature(file_id, signature):
        abort(403, 'Invalid signature.')

    with engine.connect() as connection:
