import sqlite3
from flask import Flask, request, send_file, abort
from werkzeug.utils import secure_filename
from hashlib import sha256

app = Flask(__name__)
DB_PATH = 'files.db'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}
BASE_DIR = '/secure/files/'

def secure_hash(user_id):
    return sha256(user_id.encode()).hexdigest()

def file_allowed(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def db_query(file_id, user_id):
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()
    cursor.execute("SELECT filename FROM files WHERE file_id=? AND user_id=?", (file_id, secure_hash(user_id)))
    file_data = cursor.fetchone()
    conn.close()
    return file_data

def func(file_id, user_id):
    file_data = db_query(file_id, user_id)
    if file_data:
        filename = secure_filename(file_data[0])
        if file_allowed(filename):
            file_path = os.path.join(BASE_DIR, filename)
            if os.path.exists(file_path):
                mime_type, _ = mimetypes.guess_type(file_path)
                return send_file(file_path, mimetype=mime_type)
    abort(404)

import os
import mimetypes
from flask import Flask, request, send_file, jsonify, abort
from werkzeug.utils import secure_filename
import sqlalchemy as db
from sqlalchemy.orm import sessionmaker
from sqlalchemy.exc import SQLAlchemyError
from functools import wraps

app = Flask(__name__)

DATABASE_URI = 'sqlite:///secure_audit.db'
engine = db.create_engine(DATABASE_URI)
Session = sessionmaker(bind=engine)

def require_authentication(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token or not validate_token(token):
            abort(401, 'Unauthorized access')
        return f(*args, **kwargs)
    return decorated_function

def validate_token(token):
    return token == "secure_token"

class UserFiles(db.declarative_base()):
    __tablename__ = 'user_files'
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.String, nullable=False)
    file_path = db.Column(db.String, nullable=False)

def is_valid_file_path(file_path):
    normalized_path = os.path.normpath(file_path)
    return os.path.isabs(normalized_path) and '..' not in normalized_path

@app.route('/download/<int:file_id>', methods=['GET'])
@require_authentication
def func(file_id):
    user_id = request.args.get('user_id')
    session = Session()
    try:
        record = session.query(UserFiles).filter_by(id=file_id, user_id=user_id).first()
        if not record or not os.path.isfile(record.file_path) or not is_valid_file_path(record.file_path):
            abort(404, 'File not found')
        mime_type, _ = mimetypes.guess_type(record.file_path)
        return send_file(record.file_path, mimetype=mime_type)
    except SQLAlchemyError:
        abort(500, 'Database error')
    finally:
        session.close()

if __name__ == '__main__':
    app.run(debug=True)

