app = Flask(__name__)

DATABASE_URI = 'sqlite:///files.db'
ADMIN_SECRET_KEY = 'supersecureadminkey'

engine = create_engine(DATABASE_URI)

def validate_request_headers(req):
    if 'Authorization' not in req.headers:
        abort(401)
    auth_type, _, credentials = req.headers['Authorization'].partition(' ')
    if auth_type.lower() != 'bearer' or credentials != ADMIN_SECRET_KEY:
        abort(403)

def hash_filename(filename):
    hasher = hashlib.sha256()
    hasher.update(filename.encode('utf-8'))
    return hasher.hexdigest()

def query_file_record(file_id):
    with engine.connect() as conn:
        result = conn.execute(text("SELECT filepath, content_hash FROM files WHERE id = :id"), {'id': file_id}).fetchone()
    return result

def verify_file_integrity(filepath, expected_hash):
    with open(filepath, 'rb') as f:
        file_hash = hashlib.sha256(f.read()).hexdigest()
    return file_hash == expected_hash

@app.route('/download/<int:file_id>', methods=['GET'])
def func(file_id):
    validate_request_headers(request)

    file_record = query_file_record(file_id)
    if not file_record:
        abort(404)

    filepath, expected_hash = file_record
    if not os.path.exists(filepath):
        abort(404)

    if not verify_file_integrity(filepath, expected_hash):
        abort(500)

    mime_type, _ = mimetypes.guess_type(filepath)
    return send_file(filepath, as_attachment=True, mimetype=mime_type)

@app.route('/audit', methods=['POST'])
def audit():
    validate_request_headers(request)
    with engine.connect() as conn:
        result = conn.execute(text("SELECT id, filepath FROM files")).fetchall()
    audit_results = []
    for record in result:
        file_id, filepath = record
        actual_hash = hash_filename(filepath)
        integrity_status = verify_file_integrity(filepath, actual_hash)
        audit_results.append({'file_id': file_id, 'integrity': integrity_status})
    return jsonify(audit_results)

