import os
import hashlib
import mimetypes
from urllib.parse import unquote
from flask import Flask, request, send_file, abort
from werkzeug.security import safe_join
from sqlalchemy import create_engine, text
from sqlalchemy.engine import Engine

app = Flask(__name__)

DATABASE_URI = 'sqlite:///example.db'
FILES_DIRECTORY = '/secure/file_store'
VALID_EXTENSIONS = {'.pdf', '.jpg', '.png', '.txt'}
MAX_DOWNLOAD_SIZE = 10 * 1024 * 1024

def connect_db() -> Engine:
    return create_engine(DATABASE_URI)

def clean_filename(filename: str) -> str:
    return unquote(os.path.basename(filename))

def file_allowed(filename: str) -> bool:
    return os.path.splitext(filename)[1].lower() in VALID_EXTENSIONS

def hash_validation(filename: str, user_id: int, conn: Engine) -> bool:
    query = text("SELECT file_hash FROM file_audit WHERE filename = :filename AND user_id = :user_id")
    result = conn.execute(query, {'filename': filename, 'user_id': user_id}).fetchone()
    if result:
        with open(safe_join(FILES_DIRECTORY, filename), 'rb') as f:
            file_hash = hashlib.sha256(f.read()).hexdigest()
            return file_hash == result['file_hash']
    return False

@app.route('/download', methods=['GET'])
def func():
    conn = connect_db().connect()
    user_id = request.args.get('user_id', type=int)
    filename = clean_filename(request.args.get('filename', ''))

    if not file_allowed(filename):
        abort(403)

    full_path = safe_join(FILES_DIRECTORY, filename)
    if not os.path.isfile(full_path):
        abort(404)

    if os.path.getsize(full_path) > MAX_DOWNLOAD_SIZE:
        abort(413)

    if not hash_validation(filename, user_id, conn):
        abort(403)

    mime_type, _ = mimetypes.guess_type(full_path)
    return send_file(full_path, mimetype=mime_type)

if __name__ == "__main__":
    app.run()

