import os
import hashlib
import mimetypes
import jwt
from datetime import datetime, timedelta
from sqlalchemy import create_engine, text
from flask import Flask, request, send_file, abort

DATABASE_URI = 'sqlite:///file_audit.db'
SECRET_KEY = os.getenv('SECRET_KEY', 'your-secret-key')
TOKEN_EXPIRATION_SECONDS = 3600

app = Flask(__name__)
engine = create_engine(DATABASE_URI)

def generate_token(user_id):
    payload = {
        'user_id': user_id,
        'exp': datetime.utcnow() + timedelta(seconds=TOKEN_EXPIRATION_SECONDS)
    }
    return jwt.encode(payload, SECRET_KEY, algorithm='HS256')

def verify_token(token):
    try:
        decoded = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
        return decoded['user_id']
    except jwt.ExpiredSignatureError:
        abort(401, "Token expired")
    except jwt.InvalidTokenError:
        abort(401, "Invalid token")

def get_file_record(file_id):
    with engine.connect() as conn:
        result = conn.execute(text("SELECT path, hash FROM files WHERE id = :id"), {"id": file_id}).fetchone()
        if not result:
            abort(404, "File not found")
        return result

def verify_file_integrity(file_path, expected_hash):
    sha256_hash = hashlib.sha256()
    with open(file_path, "rb") as f:
        for byte_block in iter(lambda: f.read(4096), b""):
            sha256_hash.update(byte_block)
    actual_hash = sha256_hash.hexdigest()
    return actual_hash == expected_hash

def func(file_id):
    token = request.headers.get('Authorization')
    if not token:
        abort(401, "Authorization token is required")

    user_id = verify_token(token)
    file_record = get_file_record(file_id)

    file_path, expected_hash = file_record['path'], file_record['hash']
    if not os.path.isfile(file_path):
        abort(404, "File not found on server")

    if not verify_file_integrity(file_path, expected_hash):
        abort(400, "File integrity compromised")

    mime_type, _ = mimetypes.guess_type(file_path)
    return send_file(file_path, mimetype=mime_type, as_attachment=True)

if __name__ == '__main__':
    app.run(debug=True)

