            if not os.path.isfile(file_path) or not os.access(file_path, os.R_OK):
                abort(404)

            file_extension = os.path.splitext(filename)[1]
            if file_extension not in VALID_EXTENSIONS:
                abort(403)

            mime_type, _ = mimetypes.guess_type(file_path)
