import sqlite3
import hashlib
import hmac

app = Flask(__name__)

SECRET_KEY = b'secret-key'

def verify_user_access(user_id, file_id):
    conn = sqlite3.connect('audit.db')
    try:
        cursor = conn.cursor()
        cursor.execute('SELECT access FROM file_access WHERE user_id=? AND file_id=?', (user_id, file_id))
        result = cursor.fetchone()
        return result is not None and result[0] == 1
    finally:
        conn.close()

def secure_path_join(root, *paths):
    base = os.path.abspath(root)
    file_path = os.path.abspath(os.path.join(root, *paths))
    if os.path.commonprefix([base, file_path]) != base:
        raise ValueError("Attempt to escape base directory")
    return file_path

def verify_signature(file_id, signature):
    expected_signature = hmac.new(SECRET_KEY, file_id.encode(), hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected_signature, signature)

@app.route('/download', methods=['GET'])
