    signature = request.args.get('signature')

    if not (file_id and user_id and signature):
        abort(400)

    if not verify_user_access(user_id, file_id):
        abort(403)

    if not verify_signature(file_id, signature):
        abort(403)

    try:
        file_path = secure_path_join('/secure/files', file_id)
    except ValueError:
        abort(400)

    if not os.path.isfile(file_path):
        abort(404)

