import sqlite3
import re
import os

def func(action, query=None, page=1, per_page=10, db_path='database.db'):
    if not os.path.exists(db_path):
        raise FileNotFoundError("Database file not found.")

    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()

    def secure_query(input_query):
        if not input_query or not isinstance(input_query, str):
            return ""
        safe_query = re.sub(r'[^\w\s]', '', input_query)
        return safe_query.strip().lower()

    if action == 'search':
        safe_query = secure_query(query)
        if not safe_query:
            return []

        cursor.execute("SELECT * FROM items WHERE name LIKE ?", (f'%{safe_query}%',))
        results = cursor.fetchall()

    elif action == 'pagination':
        if page < 1 or per_page < 1:
            raise ValueError("Page and per_page must be greater than 0.")

        offset = (page - 1) * per_page
        cursor.execute("SELECT * FROM items LIMIT ? OFFSET ?", (per_page, offset))
        results = cursor.fetchall()

    else:
        raise ValueError("Invalid action specified.")

    conn.close()
    return results

