from itsdangerous import TimedJSONWebSignatureSerializer as Serializer

def func(db_session: Session, query_params: Dict[str, Any], user_token: str, secret_key: str, expires_sec: int = 3600) -> Optional[Dict[str, Any]]:
    def verify_user_token(token: str, secret_key: str, expires_sec: int) -> Optional[Dict[str, Any]]:
