        self.db_path = db_path

    def _connect_db(self) -> sqlite3.Connection:
        return sqlite3.connect(self.db_path)

    def _sanitize_input(self, input_string: str) -> str:
        return re.sub(r'[^\w\s]', '', input_string)

    def func(self, search_query: Optional[str] = None, page: int = 1, page_size: int = 10) -> List[Dict[str, Any]]:
        if page_size < 1 or page_size > 100:
            raise ValueError("page_size must be between 1 and 100")

        offset = (page - 1) * page_size
        search_query = self._sanitize_input(search_query) if search_query else ''

        with self._connect_db() as conn:
            cursor = conn.cursor()
            if search_query:
                cursor.execute(
                    "SELECT id, audit_info FROM audits WHERE audit_info LIKE ? LIMIT ? OFFSET ?",
                    (f'%{search_query}%', page_size, offset)
                )
            else:
                cursor.execute("SELECT id, audit_info FROM audits LIMIT ? OFFSET ?", (page_size, offset))

            result = cursor.fetchall()

        return [{"id": row[0], "audit_info": row[1]} for row in result]

