from typing import Dict, Any, List, Union

class SecureAuditError(Exception):
    pass

def validate_input(input_data: Dict[str, Any]) -> None:
    if not isinstance(input_data, dict):
        raise SecureAuditError("Invalid input type.")
    if 'query' in input_data and not isinstance(input_data['query'], str):
        raise SecureAuditError("Search query must be a string.")
    if 'page' in input_data and (not isinstance(input_data['page'], int) or input_data['page'] <= 0):
        raise SecureAuditError("Page number must be a positive integer.")
    if 'limit' in input_data and (not isinstance(input_data['limit'], int) or input_data['limit'] <= 0):
        raise SecureAuditError("Limit must be a positive integer.")

def execute_db_query(query: str, params: tuple = ()) -> List[Dict[str, Union[str, int]]]:
    conn = sqlite3.connect('/path/to/secure/database.db')
    conn.set_trace_callback(print)
    try:
        cursor = conn.cursor()
        cursor.execute(query, params)
        columns = [column[0] for column in cursor.description]
        results = [dict(zip(columns, row)) for row in cursor.fetchall()]
    except sqlite3.DatabaseError as e:
        raise SecureAuditError("Database operation failed.")
    finally:
        conn.close()
    return results

def func(input_data: Dict[str, Any]) -> List[Dict[str, Union[str, int]]]:
    validate_input(input_data)

    query = input_data.get('query', '')
    page = input_data.get('page', 1)
    limit = input_data.get('limit', 10)

    if query:
        sanitized_query = query.replace('%', '').replace('_', '').strip()
        db_query = "SELECT * FROM records WHERE data LIKE ? LIMIT ? OFFSET ?"
        params = (f"%{sanitized_query}%", limit, (page - 1) * limit)
    else:
        db_query = "SELECT * FROM records LIMIT ? OFFSET ?"
        params = (limit, (page - 1) * limit)

    return execute_db_query(db_query, params)

