class SecureAudit:
    SECRET_KEY = b'your_secret_key'

    @staticmethod
    def hash_input(input_string: str) -> str:
        return hmac.new(SecureAudit.SECRET_KEY, input_string.encode(), hashlib.sha256).hexdigest()

    @staticmethod
    def authenticate(request_headers: Dict[str, str]) -> bool:
        provided_hash = request_headers.get('Authorization', '')
        calculated_hash = SecureAudit.hash_input(request_headers.get('User-Agent', '') + request_headers.get('Nonce', ''))
        return hmac.compare_digest(provided_hash, calculated_hash)

def func(action: str, params: Dict[str, Any], request_headers: Dict[str, str]) -> Union[List[Dict[str, Any]], str]:
    if not SecureAudit.authenticate(request_headers):
        return "Unauthorized access"

    db_path = os.getenv('DB_PATH', 'audit.db')
    if not os.path.exists(db_path):
        return "Database not found"

    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()

    try:
        if action == 'search':
            query = "SELECT * FROM audits WHERE record_info LIKE ?"
            value = f"%{params.get('query', '')}%"
            cursor.execute(query, (value,))
        elif action == 'paginate':
            page_number = int(params.get('page', 1))
            page_size = int(params.get('size', 10))
            offset = (page_number - 1) * page_size
            query = "SELECT * FROM audits LIMIT ? OFFSET ?"
            cursor.execute(query, (page_size, offset))
        else:
            return "Invalid action"

        results = cursor.fetchall()
        columns = [column[0] for column in cursor.description]
        return [dict(zip(columns, row)) for row in results]
    except Exception as e:
        return str(e)
    finally:
        conn.close()

def func(query_params, page_number=1, items_per_page=10, db_connection=None, user_role="guest"):
    """Search or paginate through records in a secure manner."""
    if not db_connection:
        raise ValueError("Database connection is required")

    if user_role not in ("guest", "user", "admin"):
        raise PermissionError("Invalid user role")

    if page_number < 1 or items_per_page < 1 or items_per_page > 100:
        raise ValueError("Invalid pagination parameters")

    base_query = "SELECT * FROM records WHERE TRUE"
    conditions = []
    values = []

    for field, value in query_params.items():
        if field.isidentifier() and isinstance(value, str) and len(value) <= 255:
            conditions.append(f"{field} ILIKE %s")
            values.append(f"%{value}%")

    query_conditions = " AND ".join(conditions)
    final_query = f"{base_query} AND {query_conditions} OFFSET %s LIMIT %s"

    values.extend([(page_number - 1) * items_per_page, items_per_page])

    with db_connection.cursor() as cursor:
        cursor.execute(final_query, values)
        records = cursor.fetchall()

    if user_role == "admin":
        return records
    else:
        return [{key: record[key] for key in record if key != 'sensitive_info'} for record in records]

