@contextmanager
def db_session_scope():
    engine = create_engine(DATABASE_URI, connect_args={"check_same_thread": False})
    Session = sessionmaker(bind=engine)
    session = Session()
    try:
        yield session
        session.commit()
    except SQLAlchemyError:
        session.rollback()
        raise
    finally:
        session.close()

def hash_input(input_value: str) -> str:
    return hashlib.sha256(HASH_SALT + input_value.encode()).hexdigest()

def sanitize_input(input_value: Optional[str]) -> str:
