        return ''
    return input_value.replace('%', '').replace('_', '').strip()

def func(search_query: Optional[str] = None, page: int = 0) -> List[Dict]:
    offset = page * PAGE_SIZE
    search_query = sanitize_input(search_query)

    with db_session_scope() as session:
        try:
            if search_query:
                hashed_query = hash_input(search_query)
                query_string = text(
                    "SELECT id, data FROM records WHERE data_hash = :hashed_query LIMIT :limit OFFSET :offset"
                )
                results = session.execute(query_string, {'hashed_query': hashed_query, 'limit': PAGE_SIZE, 'offset': offset}).fetchall()
            else:
                query_string = text("SELECT id, data FROM records LIMIT :limit OFFSET :offset")
                results = session.execute(query_string, {'limit': PAGE_SIZE, 'offset': offset}).fetchall()

            return [{'id': row['id'], 'data': row['data']} for row in results]
        except SQLAlchemyError:
            return []

