from functools import wraps

def secure_query_execution(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except sqlite3.DatabaseError as e:
            # Log error securely without revealing sensitive info
            log_error(f"Database error: {str(e)}")
            raise RuntimeError("Operation failed due to database error.")
    return wrapper

def sanitize_input(input_string: str) -> str:
    return re.sub(r'[^\w\s]', '', input_string)

def authorize_user(user_roles: List[str]) -> bool:
    required_roles = {'admin', 'user'}
    return bool(set(user_roles).intersection(required_roles))

@secure_query_execution
def func(query: Optional[str] = None, page: Optional[int] = 1, user_roles: List[str] = []) -> List[dict]:
    if not authorize_user(user_roles):
        raise PermissionError("User does not have the necessary permissions.")

    sanitized_query = sanitize_input(query) if query else None
    sanitized_page = max(1, page)
    connection = sqlite3.connect('secure_database.db')
    cursor = connection.cursor()

    base_sql = "SELECT * FROM records"
    if sanitized_query:
        base_sql += " WHERE data LIKE ?"
        cursor.execute(base_sql, (f'%{sanitized_query}%',))
    else:
        cursor.execute(base_sql)

    records = cursor.fetchall()
    connection.close()

    page_size = 10
    start_index = (sanitized_page - 1) * page_size
    paginated_records = records[start_index:start_index + page_size]

    return [{'id': rec[0], 'data': rec[1]} for rec in paginated_records]

