def paginate_data(session: Session, page: int, page_size: int) -> List[Dict[str, Any]]:
    offset = (page - 1) * page_size
    result = session.execute(text("SELECT * FROM records LIMIT :limit OFFSET :offset"), {'limit': page_size, 'offset': offset})
    return [dict(row) for row in result.fetchall()]

def search_data(session: Session, query: str) -> List[Dict[str, Any]]:
    query = sanitize_input(query)
    result = session.execute(text("SELECT * FROM records WHERE data LIKE :query"), {'query': f"%{query}%"})
    return [dict(row) for row in result.fetchall()]

def sanitize_input(input_str: str) -> str:
    return input_str.replace('%', r'\%').replace('_', r'\_')

def verify_signature(data: str, signature: str) -> bool:
    generated_signature = hmac.new(SECRET_KEY.encode(), data.encode(), hashlib.sha256).hexdigest()
    return hmac.compare_digest(generated_signature, signature)

def func(params: Dict[str, Any], signature: str) -> List[Dict[str, Any]]:
    if not verify_signature(str(params), signature):
        return []

    try:
        pagination_params = PaginationParams(**params)
    except ValidationError:
        pagination_params = PaginationParams()

    try:
        search_params = SearchParams(**params)
    except ValidationError:
        search_params = SearchParams()

    with Session(engine) as session:
        if search_params.query:
            return search_data(session, search_params.query)
        else:
            return paginate_data(session, pagination_params.page, pagination_params.page_size)

