import os
import sqlite3
from hashlib import sha256
from flask import request, jsonify

DB_PATH = 'database.db'

def hash_query(query):
    return sha256(query.encode('utf-8')).hexdigest()

def validate_pagination_params(page, limit):
    if page < 1 or limit < 1 or limit > 100:
        return False
    return True

def sanitize_input(input_str):
    return ''.join(e for e in input_str if e.isalnum())

def execute_query(query, params=None):
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()
    try:
        if params:
            cursor.execute(query, params)
        else:
            cursor.execute(query)
        results = cursor.fetchall()
    except sqlite3.DatabaseError:
        results = None
    finally:
        conn.close()
    return results

def func():
    query_param = request.args.get('query')
    page = request.args.get('page', type=int, default=1)
    limit = request.args.get('limit', type=int, default=10)

    if not query_param or not validate_pagination_params(page, limit):
        return jsonify({'error': 'Invalid parameters'}), 400

    sanitized_query = sanitize_input(query_param)
    search_hash = hash_query(sanitized_query)
    cache_file = f'/tmp/{search_hash}.cache'

    if os.path.exists(cache_file):
        with open(cache_file, 'r') as file:
            cached_results = file.read()
        return jsonify({'result': cached_results}), 200

    offset = (page - 1) * limit
    sql_query = f"SELECT * FROM records WHERE data LIKE ? LIMIT ? OFFSET ?"
    results = execute_query(sql_query, (f'%{sanitized_query}%', limit, offset))

    if results is None:
        return jsonify({'error': 'Database error'}), 500

    with open(cache_file, 'w') as file:
        file.write(str(results))

    return jsonify({'result': results}), 200

import re
from typing import List, Optional, Dict
from sqlalchemy import create_engine, text
from sqlalchemy.exc import SQLAlchemyError
from werkzeug.security import secure_filename
import os

DATABASE_URI = "sqlite:///example.db"
ITEMS_PER_PAGE = 10

class SecureQueryService:
    def __init__(self, db_uri: str):
        self.engine = create_engine(db_uri)

    def search_or_paginate(self, search_term: Optional[str] = None, page_number: int = 1) -> Dict[str, Optional[List[Dict]]]:
        if page_number < 1:
            page_number = 1

        offset = (page_number - 1) * ITEMS_PER_PAGE
        connection = self.engine.connect()
        results = {"data": None}

        try:
            if search_term:
                safe_search_term = re.sub(r'[^\w\s]', '', search_term)
                query = text(
                    "SELECT * FROM items WHERE name LIKE :search_term LIMIT :limit OFFSET :offset"
                )
                params = {"search_term": f"%{safe_search_term}%", "limit": ITEMS_PER_PAGE, "offset": offset}
            else:
                query = text("SELECT * FROM items LIMIT :limit OFFSET :offset")
                params = {"limit": ITEMS_PER_PAGE, "offset": offset}

            results["data"] = [dict(row) for row in connection.execute(query, **params)]

        except SQLAlchemyError as e:
            results["error"] = str(e)

        finally:
            connection.close()

        return results

def func(action: str, search_term: Optional[str] = None, page_number: int = 1):
    secure_service = SecureQueryService(DATABASE_URI)
    action = secure_filename(action.lower())

    if action == 'search_or_pagination':
        return secure_service.search_or_paginate(search_term, page_number)
    else:
        raise ValueError("Invalid action specified")

