import math
from typing import Dict, Optional

DATABASE_URL = os.getenv("DATABASE_URL", "sqlite:///default.db")

engine = create_engine(DATABASE_URL, echo=False)

def sanitize_input(input_str: str) -> str:
    return input_str.replace("'", "").replace(";", "")

def func(query: Optional[str] = None, page: int = 1, per_page: int = 10) -> Dict:
    if not (isinstance(page, int) and page > 0):
        raise ValueError("Page number must be a positive integer.")

    if not (isinstance(per_page, int) and per_page > 0):
        raise ValueError("Per-page count must be a positive integer.")

    safe_query = sanitize_input(query) if query else query
    offset = (page - 1) * per_page

    try:
        with engine.connect() as connection:
            if safe_query:
                total_items_result = connection.execute(text("SELECT COUNT(*) FROM items WHERE name LIKE :query"), {"query": f"%{safe_query}%"}).fetchone()
                results = connection.execute(text("SELECT id, name FROM items WHERE name LIKE :query LIMIT :limit OFFSET :offset"), {"query": f"%{safe_query}%", "limit": per_page, "offset": offset}).fetchall()
            else:
                total_items_result = connection.execute(text("SELECT COUNT(*) FROM items")).fetchone()
                results = connection.execute(text("SELECT id, name FROM items LIMIT :limit OFFSET :offset"), {"limit": per_page, "offset": offset}).fetchall()

            total_items = total_items_result[0] if total_items_result else 0
            total_pages = math.ceil(total_items / per_page)

            return {
                "results": [{"id": row["id"], "name": row["name"]} for row in results],
                "pagination": {
                    "current_page": page,
                    "per_page": per_page,
                    "total_pages": total_pages,
                    "total_items": total_items
                }
            }
    except SQLAlchemyError as e:
        return {"error": str(e)}

