import os
import sqlite3
from typing import Optional, Dict

def secure_db_connection(db_path: str) -> sqlite3.Connection:
    if not os.path.exists(db_path):
        raise FileNotFoundError("Database file not found.")
    try:
        conn = sqlite3.connect(db_path, isolation_level='EXCLUSIVE')
    except sqlite3.Error as e:
        raise ConnectionError(f"Failed to connect to database: {e}")
    return conn

def validate_input(input_data: Dict[str, Optional[str]]) -> Dict[str, str]:
    sanitized_data = {}
    for key, value in input_data.items():
        if value is not None:
            sanitized_data[key] = str(value).strip().replace("'", "''")
        else:
            sanitized_data[key] = ''
    return sanitized_data

def func(db_path: str, search_params: Dict[str, Optional[str]], page: int = 1, items_per_page: int = 10) -> Dict[str, Optional[str]]:
    conn = secure_db_connection(db_path)
    sanitized_params = validate_input(search_params)

    query_parts = []
    for column, value in sanitized_params.items():
        query_parts.append(f"{column} LIKE '%{value}%'")

    query_string = " AND ".join(query_parts)

    offset = (page - 1) * items_per_page

    cursor = conn.cursor()
    try:
        cursor.execute(f"SELECT * FROM records WHERE {query_string} LIMIT ? OFFSET ?", (items_per_page, offset))
        results = cursor.fetchall()
    except sqlite3.Error as e:
        raise RuntimeError(f"Failed to execute query: {e}")
    finally:
        cursor.close()
        conn.close()

    return {"results": results if results else None}

