        raise PermissionError("User authentication failed")

    search_query = sanitize_input(search_query) if search_query else ''
    offset = (page - 1) * per_page

    conn = sqlite3.connect('database.db')
    cur = conn.cursor()

    if search_query:
        cur.execute('SELECT * FROM records WHERE data LIKE ? LIMIT ? OFFSET ?', (f'%{search_query}%', per_page, offset))
    else:
        cur.execute('SELECT * FROM records LIMIT ? OFFSET ?', (per_page, offset))

    results = cur.fetchall()
    conn.close()

    return results

