def _is_valid_user(user_token: str) -> bool:
    expected_token = hmac.new(
        SECRET_KEY.encode(),
        msg=b'valid_user',
        digestmod=hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(user_token, expected_token)

def _sanitize_input(input_string: str) -> str:
