        raise PermissionError("Unauthorized access attempt detected.")

    conn = _establish_connection()
    try:
        cursor = conn.cursor()

        offset = (page_number - 1) * page_size
        limit = page_size

        if query:
            sanitized_query = _sanitize_input(query)
            sql_query = f"SELECT * FROM audit_logs WHERE entry LIKE '%{sanitized_query}%' LIMIT ? OFFSET ?"
            cursor.execute(sql_query, (limit, offset))
        else:
            sql_query = "SELECT * FROM audit_logs LIMIT ? OFFSET ?"
            cursor.execute(sql_query, (limit, offset))

