    try:
        query = text("SELECT * FROM records WHERE user_id = :user_id AND content ILIKE :search_query LIMIT :per_page OFFSET :offset")
        records = session.execute(query, {'user_id': user_id, 'search_query': f'%{search_query}%', 'per_page': per_page, 'offset': offset}).fetchall()
        return jsonify([dict(record) for record in records])
