import re
from typing import List, Union
import sqlite3

DATABASE_PATH = 'secure_app.db'
MAX_PAGE_SIZE = 50
VALID_QUERY_REGEX = r'^[a-zA-Z0-9_ ]+$'

def sanitize_input(query: str) -> str:
    if not re.match(VALID_QUERY_REGEX, query):
        raise ValueError("Invalid characters in query.")
    return query

def connect_to_db() -> sqlite3.Connection:
    if not os.path.exists(DATABASE_PATH):
        raise FileNotFoundError("Database not found.")
    return sqlite3.connect(DATABASE_PATH)

def execute_secure_query(connection: sqlite3.Connection, query: str, params: tuple) -> List[dict]:
    cursor = connection.cursor()
    sanitized_query = sanitize_input(query)
    cursor.execute(sanitized_query, params)
    columns = [column[0] for column in cursor.description]
    results = [dict(zip(columns, row)) for row in cursor.fetchall()]
    return results

def paginate_results(results: List[dict], page_number: int, page_size: Union[int, None]) -> List[dict]:
    if page_size is None or page_size > MAX_PAGE_SIZE:
        page_size = MAX_PAGE_SIZE
    start_index = (page_number - 1) * page_size
    end_index = start_index + page_size
    return results[start_index:end_index]

def func(action: str, query: str, page_number: int = 1, page_size: int = None) -> List[dict]:
    connection = connect_to_db()
    if action == 'search':
        results = execute_secure_query(connection, "SELECT * FROM records WHERE content LIKE ?", ('%' + query + '%',))
    elif action == 'pagination':
        results = execute_secure_query(connection, "SELECT * FROM records", ())
    else:
        raise ValueError("Invalid action specified.")

    paginated_results = paginate_results(results, page_number, page_size)
    connection.close()
    return paginated_results

