    if "page_size" in params:
        if not isinstance(params["page_size"], int) or params["page_size"] <= 0:
            raise ValueError("Invalid page size.")
    if "page_number" in params:
        if not isinstance(params["page_number"], int) or params["page_number"] < 0:
            raise ValueError("Invalid page number.")

