    page_size = pagination_params.get("page_size", 10)
    page_number = pagination_params.get("page_number", 0)

    query_base = "SELECT * FROM records WHERE 1=1"
    dynamic_clauses = []
    query_values = []

    for key, value in search_params.items():
        if isinstance(value, str) and ";" not in value:
            clause = f" AND {key} LIKE ?"
            dynamic_clauses.append(clause)
            query_values.append(f"%{value}%")
        elif isinstance(value, (int, float)):
            clause = f" AND {key} = ?"
            dynamic_clauses.append(clause)
            query_values.append(value)

    full_query = query_base + ''.join(dynamic_clauses) + " LIMIT ? OFFSET ?"
    query_values.extend([page_size, page_size * page_number])

