from typing import Optional, Dict, List, Union

class SecureAuditSearchPagination:
    def __init__(self, db_path: str):
        self.db_path = db_path
        self.validate_db_path()

    def validate_db_path(self):
        if not os.path.exists(self.db_path) or os.path.islink(self.db_path):
            raise ValueError("Invalid database path.")

    def secure_query(self, query: str, params: Optional[Dict[str, Union[str, int]]] = None) -> List[Dict[str, Union[str, int]]]:
        try:
            conn = sqlite3.connect(self.db_path, isolation_level=None)
            conn.row_factory = sqlite3.Row
            cursor = conn.cursor()
            cursor.execute("PRAGMA locking_mode = EXCLUSIVE;")

            if params:
                result = cursor.execute(query, params).fetchall()
            else:
                result = cursor.execute(query).fetchall()

            secure_result = [{key: row[key] for key in row.keys()} for row in result]
        except Exception as e:
            raise RuntimeError(f"Database query failed: {e}")
        finally:
            conn.close()
        return secure_result

    def func(self, search_query: Optional[str] = None, page: Optional[int] = None, page_size: Optional[int] = None) -> List[Dict[str, Union[str, int]]]:
        base_query = "SELECT * FROM audit_logs"
        criteria = []
        params = {}

        if search_query:
            criteria.append("message LIKE :search_query")
            params['search_query'] = f"%{search_query}%"

        if criteria:
            base_query += " WHERE " + " AND ".join(criteria)

        if page is not None and page_size is not None:
            offset = (page - 1) * page_size
            base_query += " ORDER BY timestamp DESC LIMIT :page_size OFFSET :offset"
            params.update({'page_size': page_size, 'offset': offset})
        else:
            base_query += " ORDER BY timestamp DESC LIMIT 100"

