import logging
from datetime import datetime
from hashlib import sha256
from hmac import compare_digest

DATABASE = 'config_audit.db'
CONFIG_PATH = '/etc/app/config.json'
VALID_USERS = {'admin': 'secure_hashed_pwd'}

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(message)s')

def db_connect():
    return sqlite3.connect(DATABASE)

def create_audit_table():
    with db_connect() as conn:
        conn.execute('''CREATE TABLE IF NOT EXISTS audit_log (
                            id INTEGER PRIMARY KEY,
                            user TEXT,
                            change_description TEXT,
                            timestamp TEXT
                        )''')

def hash_password(password, salt):
    return sha256((password + salt).encode()).hexdigest()

def verify_user(username, password):
    if username not in VALID_USERS:
        return False
    stored_hash = VALID_USERS[username]
    return compare_digest(stored_hash, hash_password(password, username))

def record_change(user, change_description):
    with db_connect() as conn:
        conn.execute('INSERT INTO audit_log (user, change_description, timestamp) VALUES (?, ?, ?)',
                     (user, change_description, datetime.utcnow().isoformat()))
        logging.info(f"Config change recorded: {change_description}")

def func(username, password, change_description):
    if not verify_user(username, password):
        logging.warning("Invalid user credentials attempted for config change.")
        raise PermissionError("Access Denied: Invalid credentials.")

    if not os.path.exists(CONFIG_PATH):
        logging.error("Configuration file does not exist.")
        raise FileNotFoundError("Configuration file missing.")

    with open(CONFIG_PATH, 'a') as config_file:
        config_file.write(f"\n# Change by {username} on {datetime.utcnow().isoformat()}\n")
        config_file.write(change_description + '\n')

    record_change(username, change_description)

