import os
import hashlib
import logging
from datetime import datetime
from sqlalchemy import create_engine, text
from sqlalchemy.exc import SQLAlchemyError
from cryptography.fernet import Fernet
from contextlib import contextmanager

DB_URI = os.getenv('DATABASE_URI')
ENCRYPTION_KEY = os.getenv('ENCRYPTION_KEY')
CONFIG_FILE_PATH = '/path/to/config.file'
ALLOWED_USERS = ['admin', 'config_manager']

@contextmanager
def db_session():
    engine = create_engine(DB_URI)
    connection = engine.connect()
    try:
        yield connection
    finally:
        connection.close()

def func(user_id, new_config):
    if user_id not in ALLOWED_USERS:
        logging.warning(f"Unauthorized access attempt by user: {user_id}")
        return {'status': 'unauthorized'}

    if not os.path.exists(CONFIG_FILE_PATH):
        logging.error("Configuration file does not exist.")
        return {'status': 'error', 'message': 'Config file missing'}

    with open(CONFIG_FILE_PATH, 'rb') as file:
        current_config = file.read()

    current_hash = hashlib.sha256(current_config).hexdigest()
    new_hash = hashlib.sha256(new_config.encode()).hexdigest()

    if current_hash == new_hash:
        logging.info("No changes detected in the configuration.")
        return {'status': 'no_change'}

    cipher = Fernet(ENCRYPTION_KEY)
    encrypted_config = cipher.encrypt(new_config.encode())

    with open(CONFIG_FILE_PATH, 'wb') as file:
        file.write(encrypted_config)

    log_entry = {
        'user_id': user_id,
        'timestamp': datetime.utcnow().isoformat(),
        'action': 'config_change',
        'config_hash': new_hash
    }

    try:
        with db_session() as session:
            session.execute(
                text("INSERT INTO audit_logs (user_id, timestamp, action, config_hash) VALUES (:user_id, :timestamp, :action, :config_hash)"),
                log_entry
            )
        logging.info("Configuration change recorded successfully.")
        return {'status': 'success'}
    except SQLAlchemyError as e:
        logging.error(f"Database error occurred: {str(e)}")
        return {'status': 'error', 'message': 'Database error'}

import os
import logging
from datetime import datetime
import sqlite3
from cryptography.fernet import Fernet

# Establish secure connection to the database
def get_db_connection():
    conn = sqlite3.connect('secure_config.db')
    conn.execute('PRAGMA foreign_keys = ON')
    return conn

def encrypt_data(data, key):
    fernet = Fernet(key)
    return fernet.encrypt(data.encode())

def decrypt_data(encrypted_data, key):
    fernet = Fernet(key)
    return fernet.decrypt(encrypted_data).decode()

def load_encryption_key():
    if os.path.exists('encryption.key'):
        with open('encryption.key', 'rb') as file:
            return file.read()
    else:
        raise FileNotFoundError("Encryption key not found.")

def audit_log(action, status):
    logging.basicConfig(filename='audit.log', level=logging.INFO)
    log_entry = f"{datetime.utcnow()} | Action: {action} | Status: {status}"
    logging.info(log_entry)

def func(config_id, new_config):
    encryption_key = load_encryption_key()
    conn = get_db_connection()
    try:
        current_config_encrypted = conn.execute(
            "SELECT config_data FROM configurations WHERE config_id = ?", (config_id,)
        ).fetchone()
        if current_config_encrypted is None:
            audit_log(f"Config change attempt for ID {config_id}", "Failed: Configuration not found")
            return "Configuration not found."

        current_config = decrypt_data(current_config_encrypted[0], encryption_key)
        if new_config == current_config:
            audit_log(f"Config change attempt for ID {config_id}", "Failed: No change detected")
            return "No change detected."

        new_config_encrypted = encrypt_data(new_config, encryption_key)

        conn.execute(
            "UPDATE configurations SET config_data = ? WHERE config_id = ?",
            (new_config_encrypted, config_id)
        )
        conn.commit()
        audit_log(f"Config change for ID {config_id}", "Success")
        return "Configuration updated successfully."
    except Exception as e:
        audit_log(f"Config change attempt for ID {config_id}", f"Error: {str(e)}")
        return "An error occurred during the configuration change."
    finally:
        conn.close()

import os
import datetime
import sqlite3
import hashlib
from contextlib import closing

DATABASE_PATH = 'config_audit.db'
CONFIG_FILE_PATH = '/etc/myapp/config.ini'
ADMIN_USERS = ['admin_user1', 'admin_user2']
HASH_METHOD = 'sha256'

def func(user_id, config_key, new_value):
    def is_authorized(user):
        return user in ADMIN_USERS

    def hash_value(value):
        return hashlib.new(HASH_METHOD, value.encode()).hexdigest()

    def log_change(user, key, old, new):
        timestamp = datetime.datetime.utcnow().isoformat()
        with closing(sqlite3.connect(DATABASE_PATH)) as conn:
            with conn:
                conn.execute(
                    'INSERT INTO config_changes (user_id, config_key, old_value, new_value, timestamp) VALUES (?, ?, ?, ?, ?)',
                    (user, key, old, new, timestamp)
                )

    if not os.path.isfile(CONFIG_FILE_PATH):
        raise FileNotFoundError("Configuration file not found.")

    if not is_authorized(user_id):
        raise PermissionError("User is not authorized to change configurations.")

    old_config = {}
    with open(CONFIG_FILE_PATH, 'r') as f:
        lines = f.readlines()
        for line in lines:
            key, _, value = line.partition('=')
            old_config[key.strip()] = value.strip()

    if config_key not in old_config:
        raise KeyError("Configuration key not found.")

    if hash_value(new_value) == hash_value(old_config[config_key]):
        raise ValueError("New value must be different from the old value.")

    new_lines = [f"{key}={new_value}\n" if key == config_key else line for line in lines]

    with open(CONFIG_FILE_PATH, 'w') as f:
        f.writelines(new_lines)

    log_change(user_id, config_key, old_config[config_key], new_value)

