            if hmac_hash(auth_token, current_config[0]) == hmac_hash(auth_token, new_config):
                return "No changes detected"

        new_config_hash = hmac_hash(auth_token, new_config)
        cursor.execute('INSERT INTO configurations (user_id, config_data) VALUES (?, ?) ON CONFLICT(user_id) DO UPDATE SET config_data=excluded.config_data', (user_id, new_config))
        db_connection.commit()

        log_audit(user_id, new_config_hash)
