                        format='%(asctime)s - %(message)s')

    def hash_sensitive_data(data):
        return hashlib.sha256(data.encode()).hexdigest()

    def log_audit(user, action, detail):
        try:
            timestamp = datetime.utcnow().isoformat()
            logging.info('%s - User: %s, Action: %s, Detail: %s',
                         timestamp, user, action, detail)
        except Exception as e:
            logging.error('Failed to log audit: %s', e)

    def verify_user_permissions(user):
        # In a real application, this would involve a proper role-based
        # access control check against the database or an external service
        permitted_users = {"admin", "manager"}
        return user in permitted_users

    def secure_db_connection(db_string):
        try:
            return sqlite3.connect(db_string, timeout=5, isolation_level='EXCLUSIVE')
        except sqlite3.Error as e:
            logging.error("Database connection error: %s", e)
            raise

    if not verify_user_permissions(user_id):
        log_audit(user_id, 'ACCESS_DENIED', f'Attempt to change config: {config_key}')
