    with secure_db_connection(conn_string) as conn:
        cursor = conn.cursor()
        try:
            cursor.execute("BEGIN EXCLUSIVE")
            cursor.execute("SELECT value FROM config WHERE key=?", (config_key,))
            current_value = cursor.fetchone()

            if current_value is None:
                raise ValueError("Configuration key does not exist.")

            cursor.execute("UPDATE config SET value=? WHERE key=?", (new_value, config_key))
            conn.commit()
            secure_old_value = hash_sensitive_data(current_value[0])
            secure_new_value = hash_sensitive_data(new_value)
            log_audit(user_id, 'CONFIG_CHANGE', 
                      json.dumps({"key": config_key, "old_value_hash": secure_old_value, "new_value_hash": secure_new_value}))
        except sqlite3.Error as e:
            conn.rollback()
            logging.error("Transaction failed: %s", e)
            raise

