import os
import logging
from datetime import datetime
from hashlib import sha256
from sqlalchemy import create_engine, Table, MetaData, select, update
from sqlalchemy.exc import SQLAlchemyError

DATABASE_URI = os.getenv("DATABASE_URI")
SECRET_KEY = os.getenv("SECRET_KEY")

engine = create_engine(DATABASE_URI)
metadata = MetaData(bind=engine)
UserWorkflows = Table('user_workflows', metadata, autoload_with=engine)

def hash_user_id(user_id):
    if not SECRET_KEY:
        raise EnvironmentError("SECRET_KEY is not set")
    return sha256((str(user_id) + SECRET_KEY).encode('utf-8')).hexdigest()

def check_permissions(user_id, workflow_id):
    hashed_user_id = hash_user_id(user_id)
    query = select([UserWorkflows.c.permissions]).where(
        (UserWorkflows.c.user_id == hashed_user_id) & 
        (UserWorkflows.c.workflow_id == workflow_id)
    )
    try:
        with engine.connect() as conn:
            result = conn.execute(query)
            permissions = result.scalar()
            return permissions and 'update' in permissions
    except SQLAlchemyError as e:
        logging.error(f"Database error: {e}")
        return False

def log_update(user_id, workflow_id, status):
    log_entry = f"{datetime.utcnow().isoformat()} - User: {user_id}, Workflow: {workflow_id}, Status: {status}"
    with open('audit.log', 'a') as log_file:
        log_file.write(log_entry + '\n')

def func(user_id, workflow_id, new_status):
    if not check_permissions(user_id, workflow_id):
        raise PermissionError("User does not have permission to update this workflow.")

    update_query = update(UserWorkflows).where(UserWorkflows.c.workflow_id == workflow_id).values(status=new_status)

    try:
        with engine.connect() as conn:
            conn.execute(update_query)
            log_update(user_id, workflow_id, new_status)
            return {"status": "success", "message": "Workflow status updated successfully."}
    except SQLAlchemyError as e:
        logging.error(f"Failed to update workflow status: {e}")
        return {"status": "error", "message": "An error occurred while updating the workflow status."}

