import sqlite3
from datetime import datetime
from hashlib import sha256
from hmac import compare_digest

DATABASE_PATH = os.getenv("DB_PATH", "secure_app.db")

def secure_hash(data):
    return sha256(data.encode('utf-8')).hexdigest()

def authenticate_user(user_id, token):
    conn = sqlite3.connect(DATABASE_PATH)
    try:
        cursor = conn.cursor()
        cursor.execute("SELECT token_hash FROM users WHERE user_id = ?", (user_id,))
        row = cursor.fetchone()
        if not row:
            return False
        stored_token_hash = row[0]
        return compare_digest(stored_token_hash, secure_hash(token))
    finally:
        conn.close()

def update_workflow_or_status(user_id, token, workflow_id, status):
