        cursor.execute("UPDATE workflows SET status = ?, last_updated = ? WHERE id = ?", (status, timestamp, workflow_id))
        conn.commit()

        cursor.execute("INSERT INTO audit_logs (user_id, workflow_id, old_status, new_status, timestamp) VALUES (?, ?, ?, ?, ?)", 
                       (user_id, workflow_id, current_status, status, timestamp))
