import os
import sqlite3
from datetime import datetime
import logging
import hashlib
import hmac

DATABASE_PATH = "./workflow.db"
SECRET_KEY = os.getenv("SECRET_KEY", "default_secret")

def secure_hash(data, key):
    return hmac.new(key.encode(), data.encode(), hashlib.sha256).hexdigest()

def authenticate_user(user_id, token):
    expected_token = secure_hash(user_id, SECRET_KEY)
    return hmac.compare_digest(expected_token, token)

def func(user_id, token, operation, data=None):
    if not authenticate_user(user_id, token):
        logging.error("Unauthorized user access attempt.")
        return {"status": "error", "message": "Unauthorized access"}

    conn = sqlite3.connect(DATABASE_PATH)
    cursor = conn.cursor()

    if operation == "update_workflow":
        workflow_id, new_status = data.get("workflow_id"), data.get("new_status")
        cursor.execute(
            "UPDATE workflows SET status=?, updated_at=? WHERE id=?",
            (new_status, datetime.now(), workflow_id)
        )
        conn.commit()

    elif operation == "get_status":
        workflow_id = data.get("workflow_id")
        cursor.execute("SELECT status FROM workflows WHERE id=?", (workflow_id,))
        result = cursor.fetchone()
        conn.close()
        return {"status": "success", "workflow_status": result[0] if result else "Not found"}

    else:
        logging.error("Invalid operation requested.")
        return {"status": "error", "message": "Invalid operation"}

    conn.close()
    return {"status": "success", "message": "Operation completed"}

import sqlite3
import hashlib
import hmac
from datetime import datetime
import os

SECRET_KEY = os.getenv('SECRET_KEY', 'change_this_secret_key')

def secure_compare(val1, val2):
    return hmac.compare_digest(val1, val2)

def hash_value(value):
    return hashlib.sha256(value.encode('utf-8')).hexdigest()

def func(user_id, action, status, auth_token):
    conn = sqlite3.connect('app_database.db')
    cursor = conn.cursor()

    cursor.execute("SELECT auth_token FROM users WHERE user_id=?", (user_id,))
    user_auth_token = cursor.fetchone()

    if not user_auth_token or not secure_compare(user_auth_token[0], hash_value(auth_token + SECRET_KEY)):
        conn.close()
        return {'status': 'error', 'message': 'Authentication failed'}

    if action not in ('approve', 'reject', 'update'):
        conn.close()
        return {'status': 'error', 'message': 'Invalid action'}

    cursor.execute("SELECT status FROM workflow WHERE user_id=?", (user_id,))
    current_status = cursor.fetchone()

    if not current_status:
        conn.close()
        return {'status': 'error', 'message': 'Workflow not found'}

    valid_transitions = {
        'pending': ['approve', 'reject'],
        'approved': ['update'],
        'rejected': ['update'],
        'updated': []
    }

    if action not in valid_transitions.get(current_status[0], []):
        conn.close()
        return {'status': 'error', 'message': 'Invalid status transition'}

    new_status = status if action == 'update' else action

    cursor.execute("UPDATE workflow SET status=?, last_updated=? WHERE user_id=?", 
                   (new_status, datetime.utcnow().isoformat(), user_id))
    conn.commit()
    conn.close()

    return {'status': 'success', 'message': 'Workflow updated successfully'}

import os
from datetime import datetime
import sqlite3
import logging
import hashlib

DATABASE_PATH = '/var/app/data/secure_app.db'
WORKFLOW_FILES_DIR = '/var/app/workflows'
ACCESS_LOG_FILE = '/var/app/logs/access.log'

def hash_user_id(user_id):
    return hashlib.sha256(user_id.encode()).hexdigest()

def log_access(user_id, action):
    with open(ACCESS_LOG_FILE, 'a') as log_file:
        log_file.write(f"{datetime.utcnow().isoformat()} - {hash_user_id(user_id)} - {action}\n")

def get_db_connection():
    conn = sqlite3.connect(DATABASE_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def func(user_id, workflow_id=None, status_update=None):
    if not os.path.exists(DATABASE_PATH):
        raise FileNotFoundError("The database file does not exist.")

    if workflow_id:
        if not isinstance(workflow_id, str) or not workflow_id.isalnum():
            raise ValueError("Invalid workflow id format.")

        workflow_path = os.path.join(WORKFLOW_FILES_DIR, f"{workflow_id}.json")
        if not os.path.exists(workflow_path):
            raise FileNotFoundError("The specified workflow does not exist.")

        log_access(user_id, f"Accessed workflow {workflow_id}")

        if status_update:
            conn = get_db_connection()
            cursor = conn.cursor()
            try:
                cursor.execute(
                    "UPDATE workflows SET status = ? WHERE id = ? AND user_id = ?",
                    (status_update, workflow_id, user_id)
                )
                if cursor.rowcount == 0:
                    raise PermissionError("Permission denied to update status.")
                conn.commit()
                log_access(user_id, f"Updated workflow {workflow_id} status to {status_update}")
            finally:
                conn.close()
            return {"status": "success", "message": "Workflow status updated."}
        else:
            with open(workflow_path, 'r') as wf_file:
                workflow_content = wf_file.read()
            return {"status": "success", "workflow_content": workflow_content}
    else:
        raise ValueError("No workflow id provided.")

import os
import sqlite3
import hashlib
import hmac
import json
from datetime import datetime
from typing import Dict, Any

DATABASE_PATH = 'secure_audit.db'
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret_key')

def secure_hmac(message: str, key: str) -> str:
    return hmac.new(key.encode(), message.encode(), hashlib.sha256).hexdigest()

def validate_user(token: str) -> bool:
    expected_hmac = secure_hmac('workflow_access', SECRET_KEY)
    return hmac.compare_digest(expected_hmac, token)

def fetch_user_role(user_id: int) -> str:
    conn = sqlite3.connect(DATABASE_PATH)
    try:
        cur = conn.cursor()
        cur.execute("SELECT role FROM users WHERE id = ?", (user_id,))
        row = cur.fetchone()
        return row[0] if row else 'guest'
    finally:
        conn.close()

def update_workflow_status(workflow_id: int, status: str) -> None:
    conn = sqlite3.connect(DATABASE_PATH)
    try:
        cur = conn.cursor()
        cur.execute("UPDATE workflows SET status = ? WHERE id = ?", (status, workflow_id))
        conn.commit()
    finally:
        conn.close()

def audit_log(entry: Dict[str, Any]) -> None:
    log_path = 'audit_log.json'
    entry['timestamp'] = datetime.utcnow().isoformat()
    with open(log_path, 'a') as log_file:
        json.dump(entry, log_file)
        log_file.write('\n')

def func(user_id: int, token: str, workflow_id: int, new_status: str) -> Dict[str, Any]:
    if not validate_user(token):
        return {'status': 'error', 'message': 'Invalid access token.'}

    user_role = fetch_user_role(user_id)
