import logging
from datetime import datetime, timedelta
from sqlalchemy import create_engine, text

DATABASE_URL = os.getenv('DATABASE_URL', 'sqlite:///example.db')
API_KEY = os.getenv('API_KEY')
AUTHORIZED_APPS = {'app1', 'app2'}

class UnauthorizedAccessException(Exception):
    pass

def audit_log(message, level=logging.INFO):
    logging.basicConfig(level=logging.INFO, filename='audit.log')
    logging.log(level, message)

def validate_api_key(api_key):
    if api_key != API_KEY:
        raise UnauthorizedAccessException("Invalid API key.")

def func(action, user_id, api_key, app_id):
    validate_api_key(api_key)
    if app_id not in AUTHORIZED_APPS:
        raise UnauthorizedAccessException("Unauthorized application.")

    engine = create_engine(DATABASE_URL)
    conn = engine.connect()

    try:
        result = conn.execute(text("SELECT last_login FROM users WHERE id = :user_id"), {"user_id": user_id}).fetchone()
        if not result:
            raise ValueError("User not found.")

        last_login = result['last_login']
        if datetime.utcnow() - last_login > timedelta(hours=24):
            raise UnauthorizedAccessException("User session expired.")

        if action == 'update_workflow':
            conn.execute(text("UPDATE workflows SET status = 'updated' WHERE user_id = :user_id"), {"user_id": user_id})
            audit_log(f"Workflow updated for user {user_id} by {app_id}.")
        elif action == 'update_status':
            conn.execute(text("UPDATE statuses SET status = 'updated' WHERE user_id = :user_id"), {"user_id": user_id})
            audit_log(f"Status updated for user {user_id} by {app_id}.")
