import sqlite3
import os
import hashlib
import hmac
import json
from datetime import datetime

DATABASE_PATH = 'workflow.db'
SECRET_KEY = b'supersecretkey'

def verify_signature(data, signature):
    computed_signature = hmac.new(SECRET_KEY, data.encode(), hashlib.sha256).hexdigest()
    return hmac.compare_digest(computed_signature, signature)

def update_workflow_status(workflow_id, new_status, signature):
    connection = sqlite3.connect(DATABASE_PATH)
    cursor = connection.cursor()

    query = "SELECT status FROM workflows WHERE id=?"
    cursor.execute(query, (workflow_id,))
    result = cursor.fetchone()

    if not result:
        connection.close()
        raise ValueError("Workflow not found")

    current_status = result[0]

    if verify_signature(f'{workflow_id}{current_status}', signature):
        timestamp = datetime.utcnow().isoformat()
        update_query = "UPDATE workflows SET status=?, last_updated=? WHERE id=?"
        cursor.execute(update_query, (new_status, timestamp, workflow_id))
        connection.commit()
        connection.close()
        log_entry = json.dumps({
            'workflow_id': workflow_id,
            'status': new_status,
            'timestamp': timestamp
        })
        log_to_file(log_entry)
        return {'status': 'success', 'message': 'Workflow status updated'}
    else:
        connection.close()
        raise PermissionError("Invalid signature")

def log_to_file(entry):
    with open('workflow_audit.log', 'a') as log_file:
        log_file.write(entry + '\n')

def func(data, signature):
    try:
        payload = json.loads(data)
        workflow_id = payload['workflow_id']
        new_status = payload['new_status']
        return update_workflow_status(workflow_id, new_status, signature)
    except (json.JSONDecodeError, KeyError, ValueError, PermissionError) as e:
        return {'status': 'error', 'message': str(e)}

import os
import logging
from datetime import datetime
from sqlalchemy import create_engine, text
from sqlalchemy.exc import SQLAlchemyError
from werkzeug.security import check_password_hash

DATABASE_URI = os.getenv('DATABASE_URI', 'sqlite:///:memory:')
engine = create_engine(DATABASE_URI)

logging.basicConfig(level=logging.INFO)

def authenticate_user(user_id, password_hash):
    try:
        with engine.connect() as connection:
            result = connection.execute(text("SELECT password FROM users WHERE id = :user_id"), {'user_id': user_id}).fetchone()
            if result and check_password_hash(result['password'], password_hash):
                return True
    except SQLAlchemyError as e:
        logging.error(f"DB authentication error: {e}")
    return False

def log_audit_event(user_id, action, status):
    try:
        with engine.connect() as connection:
            connection.execute(
                text("INSERT INTO audit_log (user_id, action, status, timestamp) VALUES (:user_id, :action, :status, :timestamp)"),
                {'user_id': user_id, 'action': action, 'status': status, 'timestamp': datetime.utcnow()})
    except SQLAlchemyError as e:
        logging.error(f"DB log error: {e}")

def func(user_id, password_hash, workflow_id, new_status):
    if not authenticate_user(user_id, password_hash):
        log_audit_event(user_id, 'unauthorized_access', 'failed')
        return {'error': 'Unauthorized'}

    try:
        with engine.begin() as connection:
            connection.execute(text("UPDATE workflows SET status = :status WHERE id = :workflow_id"), {'status': new_status, 'workflow_id': workflow_id})
            log_audit_event(user_id, f'workflow_status_update_to_{new_status}', 'success')
            return {'success': True}
    except SQLAlchemyError as e:
        logging.error(f"DB update error: {e}")
        log_audit_event(user_id, 'workflow_status_update', 'failed')
        return {'error': 'Database error'}

import os
import hashlib
import hmac
from datetime import datetime
from sqlalchemy.orm import sessionmaker
from sqlalchemy.exc import SQLAlchemyError
from models import Workflow, StatusUpdate, User, engine

def func(user_id, workflow_id, new_status, auth_token):
    if not isinstance(user_id, int) or not isinstance(workflow_id, int) or not new_status:
        raise ValueError("Invalid input parameters")

    def secure_compare(val1, val2):
        return hmac.compare_digest(val1, val2)

    def generate_auth_hash(user_id):
        secret_key = os.getenv('SECRET_KEY')
        return hmac.new(secret_key.encode(), str(user_id).encode(), hashlib.sha256).hexdigest()

    if not secure_compare(auth_token, generate_auth_hash(user_id)):
        raise PermissionError("Unauthorized access attempt detected")

    Session = sessionmaker(bind=engine)
    session = Session()

    try:
        user = session.query(User).filter_by(id=user_id).first()
        if not user or not user.is_active:
            raise PermissionError("Invalid or inactive user")

        workflow = session.query(Workflow).filter_by(id=workflow_id, assigned_to=user_id).first()
        if not workflow:
            raise LookupError("Workflow not found for this user")

        if new_status not in ['pending', 'in-progress', 'completed']:
            raise ValueError("Invalid status value")

        status_update = StatusUpdate(workflow_id=workflow_id, status=new_status, updated_at=datetime.utcnow())
        session.add(status_update)
        workflow.current_status = new_status
        session.commit()

    except (SQLAlchemyError, ValueError, PermissionError, LookupError) as e:
        session.rollback()
        raise e

    finally:
        session.close()

    return {"message": "Workflow status updated successfully", "workflow_id": workflow_id, "new_status": new_status}

import os
from datetime import datetime
import hashlib
import logging
import sqlite3
from contextlib import closing

DATABASE_PATH = 'example.db'
SECURITY_TOKEN = os.getenv('SECURITY_TOKEN')

def generate_audit_entry(user_id, workflow_id, status):
    timestamp = datetime.utcnow().isoformat()
    entry_string = f"{user_id}-{workflow_id}-{status}-{timestamp}"
    return hashlib.sha256(entry_string.encode('utf-8')).hexdigest()

def verify_security_token(token):
    return token == SECURITY_TOKEN

def func(user_id, workflow_id, new_status, received_token):
    if not verify_security_token(received_token):
        logging.warning("Unauthorized access attempt detected.")
        return {"status": "error", "message": "Unauthorized"}

    with closing(sqlite3.connect(DATABASE_PATH)) as conn, conn:
        cursor = conn.cursor()
        cursor.execute("SELECT status FROM workflows WHERE id = ?", (workflow_id,))
        row = cursor.fetchone()
        if not row:
            return {"status": "error", "message": "Workflow not found"}

        current_status = row[0]
        if current_status == new_status:
            return {"status": "success", "message": "No update needed"}

        audit_entry = generate_audit_entry(user_id, workflow_id, new_status)
        cursor.execute("UPDATE workflows SET status = ?, audit_entry = ?, updated_at = ? WHERE id = ?",
                       (new_status, audit_entry, datetime.utcnow(), workflow_id))

        try:
            conn.commit()
            logging.info(f"Workflow {workflow_id} updated to status {new_status} by user {user_id}.")
            return {"status": "success", "message": "Workflow updated"}
        except sqlite3.Error as e:
            logging.error(f"Database error: {e}")
            return {"status": "error", "message": "Internal server error"}

import os
import logging
import hashlib
import uuid
import psycopg2
from datetime import datetime
from psycopg2 import sql
from cryptography.fernet import Fernet

logging.basicConfig(level=logging.INFO)
DATABASE_URL = os.getenv("DATABASE_URL")
SECRET_KEY = os.getenv("SECRET_KEY")

def generate_audit_id():
    return str(uuid.uuid4())

def hash_data(data):
    return hashlib.sha256(data.encode()).hexdigest()

def encrypt_data(data, key):
    fernet = Fernet(key)
    return fernet.encrypt(data.encode())

def func(user_id, action, new_status=None, details=None):
    audit_id = generate_audit_id()
    timestamp = datetime.utcnow().isoformat()
    action_hash = hash_data(action)

    if new_status:
        new_status_encrypted = encrypt_data(new_status, SECRET_KEY)
    else:
        new_status_encrypted = None

    try:
        conn = psycopg2.connect(DATABASE_URL)
        cur = conn.cursor()
        cur.execute(sql.SQL("SELECT role FROM users WHERE id = %s"), [user_id])
        user_role = cur.fetchone()

        if not user_role or user_role[0] not in ['admin', 'manager']:
            logging.warning(f"Unauthorized access attempt by user {user_id}")
            raise PermissionError("User does not have permission to update workflow status.")

        query = sql.SQL("INSERT INTO audits (audit_id, user_id, action_hash, new_status_encrypted, details, timestamp) VALUES (%s, %s, %s, %s, %s, %s)")
        cur.execute(query, [audit_id, user_id, action_hash, new_status_encrypted, details, timestamp])
        conn.commit()

    except Exception as e:
        logging.error(f"Error in workflow status update: {e}")
        if conn:
            conn.rollback()
        raise e

    finally:
        if conn:
            conn.close()

