            'action': action,
            'user_id': user_id,
            'timestamp': logging.Formatter().formatTime(logging.LogRecord('', '', '', '', '', '', '', '', '', ''))
        }))

    if request.method == 'POST':
        data = request.get_json()
        token = request.headers.get('Token', '')

        if authenticate_user(token):
