def generate_hmac(key: bytes, message: str) -> str:
    return hmac.new(key, message.encode(), hashlib.sha256).hexdigest()


def validate_hmac(key: bytes, message: str, provided_hmac: str) -> bool:
    calculated_hmac = generate_hmac(key, message)
    return hmac.compare_digest(calculated_hmac, provided_hmac)


def connect_to_db(db_path: str) -> sqlite3.Connection:
    connection = sqlite3.connect(db_path, detect_types=sqlite3.PARSE_DECLTYPES)
    connection.row_factory = sqlite3.Row
    return connection


