    if not validate_hmac(hmac_key, f"{workflow_id}:{new_status}", provided_hmac):
        return "Unauthorized access"

    if new_status not in {"PENDING", "IN_PROGRESS", "COMPLETED", "FAILED"}:
        return "Invalid status"

    conn = connect_to_db(db_path)
    try:
        with conn:
            cursor = conn.execute(
                "SELECT status FROM workflows WHERE id = ?",
                (workflow_id,)
            )
            row = cursor.fetchone()
            if row is None:
                return "Workflow not found"
            current_status = row["status"]

            if current_status == new_status:
                return "No status change needed"

            conn.execute(
                "UPDATE workflows SET status = ?, updated_at = ? WHERE id = ?",
                (new_status, datetime.utcnow(), workflow_id)
            )
            return f"Status updated to {new_status}"
    finally:
        conn.close()

