import logging
from datetime import datetime
from typing import Optional

def sanitize_input(input_str: str) -> str:
    return ''.join(c for c in input_str if c.isalnum() or c in '-_')

def validate_user_permissions(user_id: int, resource_id: int, conn: sqlite3.Connection) -> bool:
    query = "SELECT permissions FROM user_permissions WHERE user_id = ? AND resource_id = ?"
    cursor = conn.execute(query, (user_id, resource_id))
    result = cursor.fetchone()
    return result is not None and 'update' in result[0].split(',')

def func(user_id: int, workflow_id: Optional[int] = None, status_update: Optional[str] = None):
    db_path = os.environ.get('DB_PATH', 'audit_workflow.db')

    try:
        conn = sqlite3.connect(db_path)

        if workflow_id:
            if validate_user_permissions(user_id, workflow_id, conn):
                sanitized_status = sanitize_input(status_update)
                conn.execute(
                    "UPDATE workflows SET status = ?, updated_at = ? WHERE id = ?",
                    (sanitized_status, datetime.utcnow(), workflow_id)
                )
                conn.commit()
                logging.info(f"User {user_id} updated workflow {workflow_id} to status '{sanitized_status}'")
            else:
                logging.warning(f"User {user_id} attempted to update workflow {workflow_id} without sufficient permissions")
