import json
import sqlite3
from datetime import datetime
from functools import wraps

DATABASE_PATH = 'secure_app.db'
LOG_FILE_PATH = '/var/log/secure_app.log'
EXPECTED_API_KEY_HASH = 'expected_hash_value'

def authenticate(api_key):
    hashed_key = hashlib.sha256(api_key.encode()).hexdigest()
    return hashed_key == EXPECTED_API_KEY_HASH

def log_event(event, user_id):
    if user_id.isdigit():
        with open(LOG_FILE_PATH, 'a') as log_file:
            log_entry = f'{datetime.utcnow().isoformat()} - User {user_id}: {event}\n'
            log_file.write(log_entry)

def secure_endpoint(func):
    @wraps(func)
    def wrapper(api_key, user_id, *args, **kwargs):
        if not authenticate(api_key):
            log_event('Authentication failed', user_id)
            return {'status': 'error', 'message': 'Unauthorized'}
        return func(user_id, *args, **kwargs)
    return wrapper

def update_workflow_status(connection, workflow_id, new_status):
    if all(x.isalnum() or x in ('_', '-') for x in workflow_id + new_status):
        connection.execute(
            'UPDATE workflows SET status = ? WHERE id = ?',
            (new_status, workflow_id)
        )
        connection.commit()

@secure_endpoint
def func(user_id, api_key, workflow_id, new_status):
    connection = sqlite3.connect(DATABASE_PATH)
    try:
        update_workflow_status(connection, workflow_id, new_status)
        log_event(f'Workflow {workflow_id} status updated to {new_status}', user_id)
        return {'status': 'success', 'message': 'Workflow status updated'}
    except Exception as e:
        log_event(f'Error updating workflow {workflow_id}: {str(e)}', user_id)
        return {'status': 'error', 'message': 'Failed to update workflow status'}
    finally:
