ALLOWED_STATUSES = {"Pending", "In Progress", "Completed", "Failed"}

def secure_filename(filename):
    return os.path.basename(filename)

def log_audit(event, details):
    logging.info("Audit event: %s, Details: %s", event, details)

def func(user_id, workflow_id, new_status):
    if new_status not in ALLOWED_STATUSES:
        log_audit("Unauthorized Status Update Attempt", f"User {user_id} attempted to set invalid status '{new_status}' for workflow {workflow_id}")
        raise ValueError("Invalid status update")

    conn = sqlite3.connect(DATABASE_PATH)
    try:
        conn.execute("BEGIN TRANSACTION;")
        cursor = conn.execute("SELECT status FROM workflows WHERE workflow_id = ? AND user_id = ?", (workflow_id, user_id))
