        return status in allowed_statuses

    def update_workflow_status(conn, wf_id, status, user):
        timestamp = datetime.datetime.utcnow().isoformat()
        sql = ("UPDATE workflows SET status = ?, updated_by = ?, updated_at = ? "
               "WHERE id = ? AND status != ?")
        conn.execute(sql, (status, user, timestamp, wf_id, status))
        conn.commit()

        return {'workflow_id': str(wf_id), 'new_status': status, 'timestamp': timestamp}

    if not is_status_valid(new_status):
        raise ValueError("Invalid status update requested.")

    if not os.path.isfile(db_path):
        raise FileNotFoundError("Database file not found.")

    conn = sqlite3.connect(db_path)
    try:
        conn.execute("PRAGMA foreign_keys = 1")
        conn.execute("BEGIN")
        cursor = conn.execute("SELECT id FROM users WHERE id = ?", (user_id,))
        user_exists = cursor.fetchone() is not None

        cursor = conn.execute("SELECT status FROM workflows WHERE id = ?", (workflow_id,))
