    conn = sqlite3.connect(DATABASE)
    cursor = conn.cursor()

    cursor.execute('CREATE TABLE IF NOT EXISTS records (id INTEGER PRIMARY KEY, user_id TEXT, data TEXT, hash TEXT)')

