from flask import request, jsonify
from functools import wraps

DB_PATH = 'secure_audit.db'

def secure_api_key_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-KEY')
        if api_key != os.environ.get('SECURE_API_KEY'):
            return jsonify({"error": "Unauthorized"}), 401
        return f(*args, **kwargs)
    return decorated_function

def hash_password(password):
    return sha256(password.encode()).hexdigest()

@secure_api_key_required
def func(operation, table, data=None, record_id=None):
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()

    if operation == 'create':
        columns = ', '.join(data.keys())
        placeholders = ', '.join('?' * len(data))
        query = f'INSERT INTO {table} ({columns}) VALUES ({placeholders})'
        cursor.execute(query, tuple(data.values()))
        conn.commit()
        return jsonify({"message": "Record created successfully"}), 201

    elif operation == 'read':
        query = f'SELECT * FROM {table} WHERE id = ?'
        cursor.execute(query, (record_id,))
        record = cursor.fetchone()
        if record:
            return jsonify(dict(record)), 200
        return jsonify({"error": "Record not found"}), 404

    elif operation == 'update':
        set_clause = ', '.join(f"{k} = ?" for k in data.keys())
        query = f'UPDATE {table} SET {set_clause} WHERE id = ?'
        cursor.execute(query, (*data.values(), record_id))
        conn.commit()
        return jsonify({"message": "Record updated successfully"}), 200

    elif operation == 'delete':
        query = f'DELETE FROM {table} WHERE id = ?'
        cursor.execute(query, (record_id,))
        conn.commit()
        return jsonify({"message": "Record deleted successfully"}), 200

    return jsonify({"error": "Invalid operation"}), 400

