from sqlalchemy import create_engine, Column, Integer, String
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker
from sqlalchemy.exc import IntegrityError
import os
import bcrypt

Base = declarative_base()
DATABASE_URL = os.getenv('DATABASE_URL')
engine = create_engine(DATABASE_URL)
Session = sessionmaker(bind=engine)
session = Session()

class User(Base):
    __tablename__ = 'users'
    id = Column(Integer, primary_key=True)
    username = Column(String, unique=True, nullable=False)
    password_hash = Column(String, nullable=False)

Base.metadata.create_all(engine)

def func(operation, user_data=None, username=None):
    if operation == 'create':
        if user_data and 'username' in user_data and 'password' in user_data:
            hashed_password = bcrypt.hashpw(user_data['password'].encode('utf-8'), bcrypt.gensalt())
            new_user = User(username=user_data['username'], password_hash=hashed_password)
            session.add(new_user)
            try:
                session.commit()
            except IntegrityError:
                session.rollback()
                return {"error": "Username already exists."}
            return {"success": "User created."}

    elif operation == 'read':
        if username:
            user = session.query(User).filter_by(username=username).first()
            if user:
                return {"username": user.username}
            return {"error": "User not found."}

    elif operation == 'update':
        if username and user_data and 'password' in user_data:
            user = session.query(User).filter_by(username=username).first()
            if user:
                user.password_hash = bcrypt.hashpw(user_data['password'].encode('utf-8'), bcrypt.gensalt())
                session.commit()
                return {"success": "Password updated."}
            return {"error": "User not found."}

    elif operation == 'delete':
        if username:
            user = session.query(User).filter_by(username=username).first()
            if user:
                session.delete(user)
                session.commit()
                return {"success": "User deleted."}
            return {"error": "User not found."}

    return {"error": "Invalid operation."}

