from contextlib import closing
from datetime import datetime

def func(user_id, report_type, start_date, end_date):
    if not isinstance(user_id, int) or user_id <= 0:
        raise ValueError("Invalid user ID")
    if report_type not in ['sales', 'inventory', 'employees']:
        raise ValueError("Invalid report type")

    if not isinstance(start_date, str) or not isinstance(end_date, str):
        raise ValueError("Date must be a string in YYYY-MM-DD format")

    try:
        start_date_obj = datetime.strptime(start_date, '%Y-%m-%d')
        end_date_obj = datetime.strptime(end_date, '%Y-%m-%d')
    except ValueError:
        raise ValueError("Invalid date format. Use YYYY-MM-DD.")

    if start_date_obj > end_date_obj:
        raise ValueError("Start date must be before end date")

    db_path = 'business.db'
    query_map = {
        'sales': "SELECT product_id, SUM(amount) as total_sales FROM sales WHERE user_id = ? AND date BETWEEN ? AND ? GROUP BY product_id",
        'inventory': "SELECT product_id, quantity FROM inventory WHERE user_id = ? AND last_updated BETWEEN ? AND ?",
        'employees': "SELECT employee_id, name, position FROM employees WHERE user_id = ? AND hire_date BETWEEN ? AND ?"
    }

    query = query_map[report_type]
    with closing(sqlite3.connect(db_path)) as conn:
        cursor = conn.cursor()
        cursor.execute(query, (user_id, start_date, end_date))
        results = cursor.fetchall()

    return results if results else "No records found"

