from werkzeug.security import safe_str_cmp

def func(user_id, report_type, query_params):
    if not is_authorized(user_id, report_type):
        return {"error": "Unauthorized access"}, 403

    conn = get_db_connection()
    query = build_query(report_type, query_params)

    try:
        df = pd.read_sql_query(query, conn)
        report_file = save_report_to_file(df, report_type)
        return {"report_file": report_file}, 200
    except Exception as e:
        return {"error": str(e)}, 500
    finally:
        conn.close()

def is_authorized(user_id, report_type):
    user_roles = get_user_roles(user_id)
    required_roles = get_required_roles(report_type)
    return any(safe_str_cmp(role, required_role) for role in user_roles for required_role in required_roles)

