    if 'db' not in g:
        g.db = sqlite3.connect(current_app.config['DATABASE'])
    return g.db

def build_query(report_type, query_params):
    base_query = f"SELECT * FROM {report_type} WHERE 1=1"
    for key, value in query_params.items():
        base_query += f" AND {key} = ?"
    return base_query, tuple(query_params.values())

def save_report_to_file(df, report_type):
    file_path = os.path.join(current_app.config['REPORT_DIR'], f"{report_type}_report.csv")
    df.to_csv(file_path, index=False)
    return file_path

