import sqlite3
import json
from datetime import datetime
from pathlib import Path
import os

def func(user_id, report_type, start_date, end_date):
    allowed_report_types = {'sales', 'inventory', 'customer'}
    if report_type not in allowed_report_types:
        raise ValueError("Invalid report type specified.")

    if not validate_user_access(user_id, report_type):
        raise PermissionError("User does not have access to this report type.")

    conn = sqlite3.connect('business.db')
    cursor = conn.cursor()

    query = f"""
    SELECT * FROM {report_type}_report 
    WHERE date BETWEEN ? AND ? 
    ORDER BY date;
    """
    cursor.execute(query, (start_date, end_date))
    results = cursor.fetchall()

    conn.close()

    report_data = [{
        'date': record[0],
        'value': record[1],
        'details': record[2]
    } for record in results]

    report_file = Path(f'reports/{report_type}_{datetime.now().strftime("%Y%m%d_%H%M%S")}.json')
    report_file.parent.mkdir(parents=True, exist_ok=True)

    with open(report_file, 'w') as f:
        json.dump(report_data, f)

    return str(report_file)

def validate_user_access(user_id, report_type):
    user_permissions = {
        'user1': {'sales', 'inventory'},
        'user2': {'customer'},
        'user3': {'sales', 'customer', 'inventory'}
    }
    return report_type in user_permissions.get(user_id, set())

import sqlite3
import json
from datetime import datetime

def func(start_date, end_date, user_id):
    if not isinstance(start_date, str) or not isinstance(end_date, str):
        raise ValueError("Dates must be strings in YYYY-MM-DD format")

    if not isinstance(user_id, int):
        raise ValueError("User ID must be an integer")

    try:
        datetime.strptime(start_date, '%Y-%m-%d')
        datetime.strptime(end_date, '%Y-%m-%d')
    except ValueError:
        raise ValueError("Invalid date format. Use YYYY-MM-DD")

    conn = sqlite3.connect('business_data.db')
    cursor = conn.cursor()

    query = """
    SELECT sales_data
    FROM sales
    WHERE user_id = ? AND sale_date BETWEEN ? AND ?
    """
    cursor.execute(query, (user_id, start_date, end_date))
    results = cursor.fetchall()

    conn.close()

    if not results:
        return json.dumps({"message": "No sales data found for the given period."})

    sales_summary = {"total_sales": 0, "records": []}

    for row in results:
        sales_record = json.loads(row[0])
        sales_summary["total_sales"] += sales_record.get("amount", 0)
        sales_summary["records"].append(sales_record)

    return json.dumps(sales_summary)

