import json
import sqlite3
from contextlib import closing
from hashlib import sha256
from datetime import datetime

DATABASE = 'business_report.db'

def secure_hash(value):
    return sha256(value.encode()).hexdigest()

def get_user_roles(user_id):
    with closing(sqlite3.connect(DATABASE)) as conn:
        cursor = conn.cursor()
        cursor.execute("SELECT role FROM user_roles WHERE user_id = ?", (user_id,))
        return [row[0] for row in cursor.fetchall()]

def has_permission(user_roles):
    return 'admin' in user_roles or 'report_viewer' in user_roles

def fetch_business_report(report_id):
    with closing(sqlite3.connect(DATABASE)) as conn:
        cursor = conn.cursor()
        cursor.execute("SELECT * FROM reports WHERE id = ?", (report_id,))
        return cursor.fetchone()

def log_access_attempt(user_id, report_id, timestamp):
    with closing(sqlite3.connect(DATABASE)) as conn:
        cursor = conn.cursor()
        cursor.execute("INSERT INTO access_logs (user_id, report_id, timestamp) VALUES (?, ?, ?)",
                       (user_id, report_id, timestamp))
        conn.commit()

def func(user_id, report_id):
    user_roles = get_user_roles(user_id)
    if not has_permission(user_roles):
        return json.dumps({"error": "Access denied"})

    report = fetch_business_report(report_id)
    if not report:
        return json.dumps({"error": "Report not found"})

    log_access_attempt(secure_hash(user_id), report_id, datetime.now().isoformat())

    return json.dumps({"report_id": report[0], "data": report[1]})

